 43→// ---------------------------------------------------------------------------
 44→// Sub-components
 45→// ---------------------------------------------------------------------------
 46→
 47→/**
 48→ * Step indicator -- a small numbered circle used in the pairing flow.
 49→ * Uses primary color when active, muted when dimmed.
 50→ */
 51→function StepDot({ n, dimmed }: { n: number; dimmed: boolean }) {
 52→  return (
 53→    <span
 54→      className={`flex size-5 shrink-0 items-center justify-center rounded-full text-[11px] leading-none font-semibold transition-colors duration-200 ${
 55→        dimmed ? "bg-muted text-muted-foreground/60" : "bg-primary/10 text-primary"
 56→      }`}
 57→    >
 58→      {n}
 59→    </span>
 60→  );
 61→}
 62→
 63→/**
 64→ * Portal URL hero card.
 65→ * The most important piece of information on this page -- where to go.
 66→ * Rendered with subtle depth (border + background) and two action buttons.
 67→ */
 68→function PortalCard({
 69→  url,
 70→  connected,
 71→  clients,
 72→}: {
 73→  url: string;
 74→  connected: boolean;
 75→  clients: number;
 76→}) {
 77→  return (
 78→    <div className="border-border/60 bg-muted/30 space-y-3 rounded-xl border px-4 py-4">
 79→      {/* Status line */}
 80→      <div className="flex items-center gap-2.5">
 81→        <span
 82→          className={`size-[7px] shrink-0 rounded-full ${
 83→            connected ? "bg-emerald-500 shadow-[0_0_6px_rgba(16,185,129,0.35)]" : "bg-red-400"
 84→          }`}
 85→        />
 86→        <span className="text-muted-foreground text-xs font-medium">
 87→          {connected ? "Connected to relay" : "Connecting..."}
 88→        </span>
 89→        {connected && clients > 0 && (
 90→          <span className="text-muted-foreground/70 text-[11px]">
 91→            &middot; {clients} {clients === 1 ? "client" : "clients"}
 92→          </span>
 93→        )}
 94→      </div>
 95→
 96→      {/* URL + actions */}
 97→      <div className="flex items-center gap-2">
 98→        <p className="min-w-0 flex-1 truncate font-mono text-sm leading-relaxed">{url}</p>
 99→        <Button
100→          variant="ghost"
101→          size="icon"
102→          className="size-7 shrink-0"
103→          onClick={() => {
104→            navigator.clipboard.writeText(url);
105→            toast.success("URL copied");
106→          }}
107→          title="Copy URL"
108→        >
109→          <Copy className="size-3.5" />
110→        </Button>
111→        <Button
112→          variant="ghost"
113→          size="icon"
114→          className="size-7 shrink-0"
115→          onClick={() => window.open(url, "_blank", "noopener")}
116→          title="Open in browser"
117→        >
118→          <ArrowUpRight className="size-3.5" />
119→        </Button>
120→      </div>
121→    </div>
122→  );
123→}
124→
125→/**
126→ * Pairing flow -- numbered steps that guide the user through device pairing.
127→ *
128→ * When no code is active: shows steps 1-2 with a "Generate Code" button.
129→ * When a code is active: step 2 transforms to show the code + countdown,
130→ * and step 3 appears ("device will appear below once paired").
131→ */
132→function PairingFlow({
133→  accessUrl,
134→  pairCode,
135→  countdown,
136→  isGenerating,
137→  onGenerate,
138→  onCopyCode,
139→}: {
140→  accessUrl: string | null;
141→  pairCode: string | null;
142→  countdown: number;
143→  isGenerating: boolean;
144→  onGenerate: () => void;
145→  onCopyCode: () => void;
146→}) {
147→  return (
148→    <div className="space-y-3">
149→      <h4 className="text-sm font-medium">Pair a Device</h4>
150→
151→      <div className="space-y-0.5">
152→        {/* Step 1 */}
153→        <div className="flex gap-3 py-2">
154→          <StepDot n={1} dimmed={false} />
155→          <p className="pt-px text-sm">
156→            Open{" "}
157→            {accessUrl ? (
158→              <button
159→                type="button"
160→                className="text-primary font-medium underline-offset-2 hover:underline"
161→                onClick={() => {
162→                  navigator.clipboard.writeText(accessUrl);
163→                  toast.success("URL copied");
164→                }}
165→              >
166→                the portal URL
167→              </button>
168→            ) : (
169→              <span className="text-muted-foreground">your access URL</span>
170→            )}{" "}
171→            on the other device
172→          </p>
173→        </div>
174→
175→        {/* Step 2 */}
176→        <div className="flex gap-3 py-2">
177→          <StepDot n={2} dimmed={!accessUrl && !pairCode} />
178→          <div className="min-w-0 flex-1 pt-px">
179→            {pairCode ? (
180→              <div className="space-y-2">
181→                <p className="text-sm">Enter this code on the other device</p>
182→                <div className="bg-muted/40 flex items-center justify-between rounded-lg px-4 py-3.5">
183→                  <span className="font-mono text-2xl font-bold tracking-[0.15em]">{pairCode}</span>
184→                  <Button
185→                    variant="ghost"
186→                    size="icon"
187→                    className="size-8"
188→                    onClick={onCopyCode}
189→                    title="Copy code"
190→                  >
191→                    <Copy className="size-3.5" />
192→                  </Button>
193→                </div>
194→                <p className="text-muted-foreground text-xs">
195→                  Expires in {Math.floor(countdown / 60)}:{String(countdown % 60).padStart(2, "0")}
196→                </p>
197→              </div>
198→            ) : (
199→              <div className="space-y-2.5">
200→                <p className="text-muted-foreground text-sm">Generate a one-time pairing code</p>
201→                <Button variant="outline" size="sm" onClick={onGenerate} disabled={isGenerating}>
202→                  {isGenerating && <RefreshCw className="mr-2 size-3.5 animate-spin" />}
203→                  Generate Code
204→                </Button>
205→              </div>
206→            )}
207→          </div>
208→        </div>
209→
210→        {/* Step 3 -- visible only when code is active */}
211→        {pairCode && (
212→          <div className="flex gap-3 py-2">
213→            <StepDot n={3} dimmed={false} />
214→            <p className="text-muted-foreground pt-px text-sm">
215→              The device will appear below once paired
216→            </p>
217→          </div>
218→        )}
219→      </div>
220→    </div>
221→  );
222→}
223→
224→/**
225→ * Paired devices list with revoke action per device.
226→ */
227→function DevicesList({
228→  devices,
229→  onRevoke,
230→  isRevoking,
231→}: {
232→  devices: PairedDevice[];
233→  onRevoke: (device: PairedDevice) => void;
234→  isRevoking: boolean;
235→}) {
236→  if (devices.length === 0) {
237→    return <p className="text-muted-foreground py-0.5 text-sm">No devices paired yet.</p>;
238→  }
239→
240→  return (
241→    <div className="space-y-1.5">
242→      {devices.map((device) => {
243→        const DeviceIcon = getDeviceIcon(device.user_agent);
244→        return (
245→          <div
246→            key={device.id}
247→            className="bg-muted/30 flex items-center justify-between rounded-lg px-4 py-2.5"
248→          >
249→            <div className="flex items-center gap-3">
250→              <DeviceIcon className="text-muted-foreground size-4 shrink-0" />
251→              <div>
252→                <p className="text-sm font-medium">{device.name}</p>
253→                <p className="text-muted-foreground text-xs">
254→                  {timeAgo(device.last_seen_at)}
255→                  {device.ip_address ? ` \u00b7 ${device.ip_address}` : ""}
256→                </p>
257→              </div>
258→            </div>
259→            <Button
260→              variant="ghost"
261→              size="icon"
262→              className="text-muted-foreground hover:text-destructive size-7"
263→              onClick={() => onRevoke(device)}
264→              disabled={isRevoking}
265→              title={`Revoke ${device.name}`}
266→            >
267→              <Trash2 className="size-3.5" />
268→            </Button>
269→          </div>
270→        );
271→      })}
272→    </div>
273→  );
274→}
275→
276→// ---------------------------------------------------------------------------
277→// Main Section
278→// ---------------------------------------------------------------------------
279→
280→/**
281→ * Unified Access settings section.
282→ *
283→ * Hierarchy:
284→ *   1. Toggle + hero portal card (URL, status, copy/open)
285→ *   2. Guided pairing flow (numbered steps with inline code generation)
286→ *   3. Paired devices list
287→ *
288→ * The portal URL is the hero because it answers the first question every
289→ * user has: "where do I go?" The pairing code is step 2 in that flow.
290→ */
291→export function AccessSection({ settings, saveSetting }: SettingsSectionProps) {
292→  const enabled = settings.remote_access_enabled === true;
293→
294→  // Remote access queries -- only active when enabled
295→  const devicesQuery = usePairedDevices(enabled);
296→  const relayQuery = useRelayStatus(enabled);
297→  const generateCodeMutation = useGeneratePairCode();
298→  const revokeDeviceMutation = useRevokeDevice();
299→
300→  // Pairing code state
301→  const [pairCode, setPairCode] = useState<string | null>(null);
302→  const [codeExpiresAt, setCodeExpiresAt] = useState(0);
303→  const [countdown, setCountdown] = useState(0);
304→
305→  // Countdown timer for pairing code expiry
306→  useEffect(() => {
307→    if (!pairCode || codeExpiresAt <= 0) return;
308→    const tick = () => {
309→      const remaining = Math.max(0, Math.ceil((codeExpiresAt - Date.now()) / 1000));
310→      setCountdown(remaining);
311→      if (remaining <= 0) {
312→        setPairCode(null);
313→        setCodeExpiresAt(0);
314→      }
315→    };
316→    tick();
317→    const interval = setInterval(tick, 1000);
318→    return () => clearInterval(interval);
319→  }, [pairCode, codeExpiresAt]);
320→
321→  // -- Handlers --
322→
323→  const handleToggle = useCallback(
324→    async (on: boolean) => {
325→      const ok = await saveSetting("remote_access_enabled", on);
326→      if (ok) {
327→        toast.success(on ? "Remote access enabled" : "Remote access disabled");
328→        if (!on) {
329→          setPairCode(null);
330→          setCodeExpiresAt(0);
331→        }
332→      }
333→    },
334→    [saveSetting]
335→  );
336→
337→  async function handleGenerateCode() {
338→    try {
339→      const result = await generateCodeMutation.mutateAsync();
340→      setPairCode(result.code);
341→      setCodeExpiresAt(Date.now() + result.expires_in_seconds * 1000);
342→    } catch (error) {
343→      toast.error(`Failed to generate code: ${getErrorMessage(error)}`);
344→    }
345→  }
346→
347→  async function handleRevokeDevice(device: PairedDevice) {
348→    try {
349→      await revokeDeviceMutation.mutateAsync(device.id);
350→      toast.success(`Revoked "${device.name}"`);
351→    } catch (error) {
352→      toast.error(`Failed to revoke device: ${getErrorMessage(error)}`);
353→    }
354→  }
355→
356→  function handleCopyCode() {
357→    if (!pairCode) return;
358→    navigator.clipboard.writeText(pairCode);
359→    toast.success("Code copied");
360→  }
361→
362→  // -- Derived values --
363→
364→  const relayStatus = relayQuery.data;
365→  const devices = devicesQuery.data ?? [];
366→
367→  // Derive web app URL from relay WebSocket URL
368→  // wss://relay.rundeus.com -> https://app.rundeus.com/connect/{serverId}
369→  const accessUrl = (() => {
370→    if (!relayStatus?.relayUrl || !relayStatus.serverId) return null;
371→    try {
372→      const url = new URL(relayStatus.relayUrl);
373→      const host = url.hostname;
374→      const domain = host.replace(/^relay\./, "app.");
375→      return `https://${domain}/connect/${relayStatus.serverId}`;
376→    } catch {
377→      return null;
378→    }
379→  })();
380→
381→  // -- Render --
382→
383→  return (
384→    <div className="space-y-6">
385→      {/* Header */}
386→      <div>
387→        <h3 className="text-base font-semibold">Connect</h3>
388→        <p className="text-muted-foreground mt-1 text-sm">
389→          Access Deus from your phone or another browser.
390→        </p>
391→      </div>
392→
393→      {/* Master toggle */}
394→      <div className="flex items-center justify-between">
395→        <div>
396→          <Label htmlFor="remote-access-toggle" className="text-sm">
397→            Enable remote access
398→          </Label>
399→          <p className="text-muted-foreground text-xs">
400→            Connects to the cloud relay so other devices can reach this machine.
401→          </p>
402→        </div>
403→        <Switch id="remote-access-toggle" checked={enabled} onCheckedChange={handleToggle} />
404→      </div>
405→
406→      {/* ----- Everything below is gated on the toggle ----- */}
407→
408→      {enabled && (
409→        <>
410→          {/* Portal card -- hero element: URL + status */}
411→          {accessUrl && relayStatus && (
412→            <PortalCard
413→              url={accessUrl}
414→              connected={relayStatus.connected}
415→              clients={relayStatus.clients}
416→            />
417→          )}
418→
419→          {/* Disconnected state without URL -- relay not configured yet */}
420→          {relayStatus && !accessUrl && (
421→            <div className="bg-muted/30 flex items-center gap-2.5 rounded-lg px-4 py-3">
422→              <span className="size-[7px] shrink-0 rounded-full bg-amber-400" />
423→              <span className="text-muted-foreground text-sm">
424→                {relayStatus.connected
425→                  ? "Connected — waiting for server ID..."
426→                  : "Connecting to relay..."}
427→              </span>
428→            </div>
429→          )}
430→
431→          <Separator />
432→
433→          {/* Guided pairing flow */}
434→          <PairingFlow
435→            accessUrl={accessUrl}
436→            pairCode={pairCode}
437→            countdown={countdown}
438→            isGenerating={generateCodeMutation.isPending}
439→            onGenerate={handleGenerateCode}
440→            onCopyCode={handleCopyCode}
441→          />
442→
443→          <Separator />
444→
445→          {/* Paired devices */}
446→          <div className="space-y-3">
447→            <div className="flex items-center gap-2">
448→              <h4 className="text-sm font-medium">Paired Devices</h4>
449→              {devices.length > 0 && (
450→                <Badge variant="secondary" className="text-[11px]">
451→                  {devices.length}
452→                </Badge>
453→              )}
454→            </div>
455→            <DevicesList
456→              devices={devices}
457→              onRevoke={handleRevokeDevice}
458→              isRevoking={revokeDeviceMutation.isPending}
459→            />
460→          </div>
461→        </>
462→      )}
463→    </div>
464→  );
465→}
