 32→// ---- Constants ----
 33→
 34→const MAX_ACTIVE_CODES = 5;
 35→const CODE_TTL_MS = 15 * 60 * 1000; // 15 minutes
 36→const RATE_LIMIT_FAILURES = 10;
 37→const RATE_LIMIT_LOCKOUT_MS = 5 * 60 * 1000; // 5 minutes
 38→
 39→// 100 short, memorable words for pairing codes
 40→const WORD_LIST = [
