143→// ---- In-memory state ----
144→
145→const activeCodes = new Map<string, PairingCode>();
146→const rateLimits = new Map<string, RateLimitEntry>();
147→
148→// ---- Pairing Codes ----
149→
150→/** Generate a WORD-NNNN pairing code. Returns the code string and its expiry. */
151→export function generatePairCode(): { code: string; expiresAt: number } {
152→  // Evict expired codes first
153→  const now = Date.now();
154→  for (const [key, entry] of activeCodes) {
155→    if (entry.expiresAt <= now) activeCodes.delete(key);
156→  }
157→
158→  // Enforce max active codes
159→  if (activeCodes.size >= MAX_ACTIVE_CODES) {
160→    // Evict oldest
161→    let oldestKey: string | null = null;
162→    let oldestTime = Infinity;
163→    for (const [key, entry] of activeCodes) {
164→      if (entry.createdAt < oldestTime) {
165→        oldestTime = entry.createdAt;
166→        oldestKey = key;
167→      }
168→    }
169→    if (oldestKey) activeCodes.delete(oldestKey);
170→  }
171→
172→  const word = WORD_LIST[randomInt(WORD_LIST.length)];
173→  const number = String(randomInt(1000, 10000)); // 1000-9999
174→  const code = `${word}-${number}`;
175→  const expiresAt = now + CODE_TTL_MS;
176→
177→  activeCodes.set(code, { code, createdAt: now, expiresAt });
178→  return { code, expiresAt };
179→}
180→
181→/** Validate and consume a pairing code. Returns true if valid (one-time use). */
182→export function validatePairCode(code: string): boolean {
183→  const upper = code.toUpperCase().trim();
184→  const entry = activeCodes.get(upper);
185→  if (!entry) {
186→    console.log(`[Auth] Code "${upper}" not found. Active codes: ${activeCodes.size}`);
187→    return false;
188→  }
189→  if (entry.expiresAt <= Date.now()) {
190→    activeCodes.delete(upper);
191→    return false;
192→  }
193→  // One-time use — delete immediately
194→  activeCodes.delete(upper);
195→  return true;
196→}
197→
198→/** Get number of active (non-expired) pairing codes. */
199→export function getActiveCodeCount(): number {
200→  const now = Date.now();
201→  for (const [key, entry] of activeCodes) {
202→    if (entry.expiresAt <= now) activeCodes.delete(key);
203→  }
204→  return activeCodes.size;
205→}
206→
207→// ---- Device Tokens ----
208→
209→function hashToken(token: string): string {
210→  return createHash("sha256").update(token).digest("hex");
211→}
212→
213→function generateId(): string {
214→  return randomBytes(16).toString("hex");
215→}
216→
217→/** Create a new device token. Returns the raw token (only shown once) and device record. */
218→export function createDeviceToken(
219→  name: string,
220→  ip: string | null,
221→  userAgent: string | null
222→): { token: string; device: PairedDevice } {
223→  const token = randomBytes(32).toString("hex");
224→  const tokenHash = hashToken(token);
225→  const id = generateId();
226→
227→  const db = getDatabase();
228→  db.prepare(
229→    `
230→    INSERT INTO paired_devices (id, name, token_hash, ip_address, user_agent)
231→    VALUES (?, ?, ?, ?, ?)
232→  `
233→  ).run(id, name || "Unknown Device", tokenHash, ip, userAgent);
234→
235→  const device = db.prepare("SELECT * FROM paired_devices WHERE id = ?").get(id) as PairedDevice;
236→  return { token, device };
237→}
238→
239→/** Validate a raw Bearer token. Returns the device if valid, null otherwise. */
240→export function validateDeviceToken(token: string): PairedDevice | null {
241→  const tokenHash = hashToken(token);
242→  const db = getDatabase();
243→  return (
244→    (db
245→      .prepare("SELECT * FROM paired_devices WHERE token_hash = ?")
246→      .get(tokenHash) as PairedDevice) ?? null
247→  );
248→}
249→
250→/** Update last_seen_at for a device by token hash. */
251→export function updateLastSeen(tokenHash: string): void {
252→  const db = getDatabase();
253→  db.prepare("UPDATE paired_devices SET last_seen_at = datetime('now') WHERE token_hash = ?").run(
254→    tokenHash
255→  );
256→}
257→
258→/** List all paired devices (token_hash excluded from the returned objects for safety). */
259→export function listDevices(): Omit<PairedDevice, "token_hash">[] {
260→  const db = getDatabase();
261→  const rows = db
262→    .prepare(
263→      "SELECT id, name, ip_address, user_agent, last_seen_at, created_at FROM paired_devices ORDER BY created_at DESC"
264→    )
265→    .all() as Omit<PairedDevice, "token_hash">[];
266→  return rows;
267→}
268→
269→/** Revoke (delete) a paired device by id. Returns true if a row was deleted. */
270→export function revokeDevice(id: string): boolean {
271→  const db = getDatabase();
272→  const result = db.prepare("DELETE FROM paired_devices WHERE id = ?").run(id);
273→  return result.changes > 0;
274→}
275→
276→// ---- Rate Limiting (per IP) ----
277→
278→/** Check if an IP is rate-limited. Returns lockout remaining ms or 0. */
279→export function checkRateLimit(ip: string): number {
280→  const entry = rateLimits.get(ip);
281→  if (!entry) return 0;
282→  const now = Date.now();
283→  if (entry.lockedUntil > now) return entry.lockedUntil - now;
284→  return 0;
285→}
286→
287→/** Record a failed pairing attempt for an IP. */
288→export function recordFailure(ip: string): void {
289→  const entry = rateLimits.get(ip) ?? { failures: 0, lockedUntil: 0 };
290→  entry.failures += 1;
291→  if (entry.failures >= RATE_LIMIT_FAILURES) {
292→    entry.lockedUntil = Date.now() + RATE_LIMIT_LOCKOUT_MS;
293→  }
294→  rateLimits.set(ip, entry);
295→}
296→
297→/** Reset rate limit for an IP (called on successful pairing). */
298→export function resetRateLimit(ip: string): void {
299→  rateLimits.delete(ip);
300→}
301→
302→// ---- Relay Credentials ----
303→
304→/** Generate relay credentials (server_id + relay_token). Stores in preferences.json. */
305→export function generateRelayCredentials(): { serverId: string; relayToken: string } {
306→  const serverId = randomBytes(4).toString("hex"); // 8-char hex
307→  const relayToken = randomBytes(32).toString("hex");
308→  saveSetting("relay_server_id", serverId);
309→  saveSetting("relay_token", relayToken);
310→  return { serverId, relayToken };
311→}
312→
313→/** Get stored relay credentials, or null if not yet generated. */
314→export function getRelayCredentials(): { serverId: string; relayToken: string } | null {
315→  const serverId = getSetting("relay_server_id");
316→  const relayToken = getSetting("relay_token");
317→  if (!serverId || !relayToken) return null;
318→  return { serverId, relayToken };
319→}
320→
321→// ---- Test Helpers (exported for testing only) ----
322→
323→export function _clearAll(): void {
324→  activeCodes.clear();
325→  rateLimits.clear();
326→}
