 1→// backend/src/routes/remote-auth.ts
 2→// Auth endpoints for remote access pairing and device management.
 3→// POST /remote-auth/pair — public, rate-limited, exchanges code for token
 4→// POST /remote-auth/generate-pair-code — localhost-only, creates a new code
 5→// GET /remote-auth/devices — localhost-only, lists paired devices
 6→// DELETE /remote-auth/devices/:id — localhost-only, revokes a device
 7→
 8→import { Hono } from "hono";
 9→import { createMiddleware } from "hono/factory";
10→import { parseBody, PairBody } from "../lib/schemas";
11→import {
12→  generatePairCode,
13→  validatePairCode,
14→  createDeviceToken,
15→  listDevices,
16→  revokeDevice,
17→  checkRateLimit,
18→  recordFailure,
19→  resetRateLimit,
20→} from "../services/remote-auth.service";
21→import { isLocalhost, getClientIp } from "../lib/network";
22→
23→const app = new Hono();
24→
25→/** Reject non-localhost requests with 403. Relay-bridged requests are trusted. */
26→const localhostOnly = createMiddleware(async (c, next) => {
27→  if (c.env?.relayBridged) {
28→    await next();
29→    return;
30→  }
31→  if (!isLocalhost(getClientIp(c))) {
32→    return c.json({ error: "This endpoint is only available from localhost" }, 403);
33→  }
34→  await next();
35→});
36→
37→// POST /remote-auth/pair — public, exchanges pairing code for device token
38→app.post("/remote-auth/pair", async (c) => {
39→  const clientIp = getClientIp(c);
40→
41→  // Rate limit check
42→  if (clientIp) {
43→    const lockout = checkRateLimit(clientIp);
44→    if (lockout > 0) {
45→      return c.json({ error: "Too many failed attempts. Try again later." }, 429);
46→    }
47→  }
48→
49→  const { code, deviceName } = parseBody(PairBody, await c.req.json());
50→
51→  if (!validatePairCode(code)) {
52→    if (clientIp) recordFailure(clientIp);
53→    return c.json({ error: "Invalid or expired pairing code" }, 401);
54→  }
55→
56→  // Successful pairing — create device token
57→  if (clientIp) resetRateLimit(clientIp);
58→  const userAgent = c.req.header("user-agent") ?? null;
59→  const { token, device } = createDeviceToken(
60→    deviceName ?? "Unknown Device",
61→    clientIp ?? null,
62→    userAgent
63→  );
64→
65→  return c.json({
66→    token,
67→    device: {
68→      id: device.id,
69→      name: device.name,
70→      created_at: device.created_at,
71→    },
72→  });
73→});
74→
75→// POST /remote-auth/generate-pair-code — localhost-only
76→app.post("/remote-auth/generate-pair-code", localhostOnly, (c) => {
77→  const { code, expiresAt } = generatePairCode();
78→  const expiresInSeconds = Math.round((expiresAt - Date.now()) / 1000);
79→
80→  return c.json({ code, expires_in_seconds: expiresInSeconds });
81→});
82→
83→// GET /remote-auth/devices — localhost-only
84→app.get("/remote-auth/devices", localhostOnly, (c) => {
85→  return c.json({ devices: listDevices() });
86→});
87→
88→// DELETE /remote-auth/devices/:id — localhost-only
89→app.delete("/remote-auth/devices/:id", localhostOnly, (c) => {
90→  const id = c.req.param("id");
91→  const deleted = revokeDevice(id);
92→  if (!deleted) {
93→    return c.json({ error: "Device not found" }, 404);
94→  }
95→  return c.json({ success: true });
96→});
97→
98→export default app;
99→

  1→// backend/src/services/ws.service.ts
  2→// WebSocket connection manager for remote access.
  3→// Manages connected clients, heartbeat pings, message routing, and protocol dispatch.
  4→
  5→import { match } from "ts-pattern";
  6→import type { WSContext } from "hono/ws";
  7→
  8→/** Minimal interface for sending/closing WebSocket-like connections.
  9→ *  WSContext already satisfies this — used to also accept virtual relay connections. */
 10→export interface WsSendable {
 11→  send(data: string | ArrayBuffer): void;
 12→  close(code?: number, reason?: string): void;
 13→}
 14→
 15→export interface WsConnection {
 16→  id: string;
 17→  ws: WsSendable;
 18→  deviceId: string | null;
 19→  lastPong: number;
 20→  /** True for relay-tunneled connections (skip direct heartbeat pings) */
 21→  isVirtual?: boolean;
 22→}
 23→
 24→// ---- State ----
 25→
 26→const connections = new Map<string, WsConnection>();
 27→let heartbeatInterval: ReturnType<typeof setInterval> | null = null;
 28→
 29→const HEARTBEAT_INTERVAL_MS = 30_000;
 30→const HEARTBEAT_TIMEOUT_MS = 10_000;
 31→
 32→// ---- Public API ----
 33→
 34→/** Register a new WebSocket connection. Returns the connection ID. */
 35→export function addConnection(ws: WsSendable, deviceId: string | null, isVirtual = false): string {
 36→  const id = crypto.randomUUID();
 37→  connections.set(id, {
 38→    id,
 39→    ws,
 40→    deviceId,
 41→    lastPong: Date.now(),
 42→    isVirtual,
 43→  });
 44→
 45→  startHeartbeat();
 46→  return id;
 47→}
 48→
 49→/** Remove a connection by ID. */
 50→export function removeConnection(id: string): void {
 51→  connections.delete(id);
 52→  if (connections.size === 0) stopHeartbeat();
 53→}
 54→
 55→/** Get a connection by ID. */
 56→export function getConnection(id: string): WsConnection | undefined {
 57→  return connections.get(id);
 58→}
 59→
 60→/** Record a pong from a client. */
 61→export function recordPong(id: string): void {
 62→  const conn = connections.get(id);
 63→  if (conn) conn.lastPong = Date.now();
 64→}
 65→
 66→/** Broadcast a message to all connected clients. */
 67→export function broadcast(message: string): void {
 68→  for (const conn of connections.values()) {
 69→    try {
 70→      conn.ws.send(message);
 71→    } catch {
 72→      // Connection may have closed — will be cleaned up on next heartbeat
 73→    }
 74→  }
 75→}
 76→
 77→/** Get number of active connections. */
 78→export function getConnectionCount(): number {
 79→  return connections.size;
 80→}
 81→
 82→/** Close all connections and stop heartbeat (for shutdown). */
 83→export function closeAll(): void {
 84→  stopHeartbeat();
 85→  for (const conn of connections.values()) {
 86→    try {
 87→      conn.ws.close(1001, "Server shutting down");
 88→    } catch {
 89→      // Best-effort
 90→    }
 91→  }
 92→  connections.clear();
 93→}
 94→
 95→// ---- Heartbeat ----
 96→
 97→function startHeartbeat(): void {
 98→  if (heartbeatInterval) return;
 99→  heartbeatInterval = setInterval(checkHeartbeats, HEARTBEAT_INTERVAL_MS);
100→}

 1→// backend/src/middleware/remote-auth.ts
 2→// Bearer token validation for remote access.
 3→// Localhost requests are exempt (desktop app needs zero auth changes).
 4→// Public paths (health, pairing) are also exempt.
 5→
 6→import { createMiddleware } from "hono/factory";
 7→import {
 8→  validateDeviceToken,
 9→  updateLastSeen,
10→  checkRateLimit,
11→  type PairedDevice,
12→} from "../services/remote-auth.service";
13→import { isLocalhost, getClientIp } from "../lib/network";
14→
15→const PUBLIC_PATHS = new Set(["/api/health", "/api/remote-auth/pair"]);
16→
17→/**
18→ * Auth middleware for remote access.
19→ * 1. Relay-bridged (via Hono env bindings) → skip auth
20→ * 2. Localhost → skip auth entirely
21→ * 3. Public paths → skip auth
22→ * 4. Rate-limited IP → 429
23→ * 5. Valid Bearer token → attach device to context, update last_seen
24→ * 6. Missing/invalid token → 401
25→ */
26→export const authMiddleware = createMiddleware(async (c, next) => {
27→  // In-process requests from the HTTP-over-WS bridge pass relayBridged via
28→  // Hono env bindings. This is structurally impossible to spoof — external
29→  // HTTP requests never pass env bindings to app.fetch().
30→  if (c.env?.relayBridged) {
31→    await next();
32→    return;
33→  }
34→
35→  const clientIp = getClientIp(c);
36→
37→  // Localhost exempt — desktop app unchanged
38→  if (isLocalhost(clientIp)) {
39→    await next();
40→    return;
41→  }
42→
43→  // Public paths exempt
44→  if (PUBLIC_PATHS.has(c.req.path)) {
45→    await next();
46→    return;
47→  }
48→
49→  // Rate limit check
50→  if (clientIp) {
51→    const lockout = checkRateLimit(clientIp);
52→    if (lockout > 0) {
53→      return c.json({ error: "Too many failed attempts. Try again later." }, 429);
54→    }
55→  }
56→
57→  // Bearer token validation
58→  const authHeader = c.req.header("authorization");
59→  if (!authHeader?.startsWith("Bearer ")) {
60→    return c.json({ error: "Authentication required" }, 401);
61→  }
62→
63→  const token = authHeader.slice(7);
64→  const device = validateDeviceToken(token);
65→  if (!device) {
66→    return c.json({ error: "Invalid or revoked token" }, 401);
67→  }
68→
69→  // Update last seen (fire-and-forget — don't block the request)
70→  updateLastSeen(device.token_hash);
71→
72→  // Strip token_hash before attaching to context — downstream handlers don't need it
73→  const { token_hash: _, ...safeDevice } = device;
74→  c.set("device", safeDevice);
75→
76→  await next();
77→});
78→

