  1→// Browser gate page for remote device pairing.
  2→// Shown when a non-localhost browser accesses OpenDevs without a valid token.
  3→// Provides a split input (WORD + NUMBER) to enter a pairing code.
  4→//
  5→// In relay mode (web-production), pairing happens through a one-shot WebSocket
  6→// to the relay's /pair endpoint. In direct mode (web-dev with remote host),
  7→// pairing POSTs to the backend's /api/remote-auth/pair endpoint.
  8→
  9→import { useState, useRef, useEffect, useCallback } from "react";
 10→import { Button } from "@/components/ui/button";
 11→import { Input } from "@/components/ui/input";
 12→import { Label } from "@/components/ui/label";
 13→import { Loader2 } from "lucide-react";
 14→import { isRelayMode, RELAY_BASE_URL } from "@/shared/config/backend.config";
 15→
 16→interface PairGatePageProps {
 17→  onPaired: (token: string, deviceName?: string) => void;
 18→  /** Server ID for relay mode pairing. Extracted from route params by ServerLayout. */
 19→  serverId?: string;
 20→}
 21→
 22→/** Parse ?pair=WORD-NNNN from URL params. */
 23→function getPairFromUrl(): { word: string; number: string } | null {
 24→  const params = new URLSearchParams(window.location.search);
 25→  const pair = params.get("pair");
 26→  if (!pair) return null;
 27→  const match = pair.match(/^([A-Za-z]+)-(\d{4})$/);
 28→  if (!match) return null;
 29→  return { word: match[1].toUpperCase(), number: match[2] };
 30→}
 31→
 32→/** Extract serverId from the current URL pathname (/s/{serverId}/...). */
 33→function getServerIdFromUrl(): string | null {
 34→  const match = window.location.pathname.match(/^\/s\/([^/]+)/);
 35→  return match ? match[1] : null;
 36→}
 37→
 38→/**
 39→ * Pair via the relay's one-shot /pair WebSocket endpoint.
 40→ * Opens a WS to wss://relay.rundeus.com/api/servers/{serverId}/pair,
 41→ * sends the pairing code, and waits for pair_success or pair_failed.
 42→ */
 43→function pairViaRelay(
 44→  serverId: string,
 45→  code: string,
 46→  deviceName: string
 47→): Promise<{ token: string }> {
 48→  return new Promise((resolve, reject) => {
 49→    const url = `${RELAY_BASE_URL}/api/servers/${encodeURIComponent(serverId)}/pair`;
 50→    const ws = new WebSocket(url);
 51→    const timeout = setTimeout(() => {
 52→      ws.close();
 53→      reject(new Error("Pairing timed out"));
 54→    }, 30_000);
 55→
 56→    ws.onopen = () => {
 57→      ws.send(JSON.stringify({ type: "pair_request", code, deviceName }));
 58→    };
 59→
 60→    ws.onmessage = (evt) => {
 61→      clearTimeout(timeout);
 62→      try {
 63→        const msg = JSON.parse(evt.data as string);
 64→        if (msg.type === "pair_success" && msg.token) {
 65→          resolve({ token: msg.token });
 66→        } else if (msg.type === "pair_failed") {
 67→          reject(new Error(msg.message || "Pairing failed"));
 68→        } else {
 69→          reject(new Error("Unexpected response from relay"));
 70→        }
 71→      } catch {
 72→        reject(new Error("Invalid response from relay"));
 73→      }
 74→      ws.close();
 75→    };
 76→
 77→    ws.onerror = () => {
 78→      clearTimeout(timeout);
 79→      reject(new Error("Could not connect to relay"));
 80→    };
 81→
 82→    ws.onclose = (evt) => {
 83→      clearTimeout(timeout);
 84→      // If not resolved/rejected yet, treat as error
 85→      if (evt.code !== 1000) {
 86→        reject(new Error("Connection closed unexpectedly"));
 87→      }
 88→    };
 89→  });
 90→}
 91→
 92→/**
 93→ * Pair via direct HTTP POST to the backend (non-relay mode).
 94→ */
 95→async function pairViaDirect(
 96→  code: string,
 97→  deviceName: string
 98→): Promise<{ token: string; device?: { name: string } }> {
 99→  const baseUrl = `${window.location.protocol}//${window.location.host}`;
100→  const response = await fetch(`${baseUrl}/api/remote-auth/pair`, {
101→    method: "POST",
102→    headers: { "Content-Type": "application/json" },
103→    body: JSON.stringify({ code, deviceName }),
104→  });
105→
106→  if (!response.ok) {
107→    const data = await response.json().catch(() => null);
108→    throw new Error(data?.error ?? "Invalid pairing code");
109→  }
110→
111→  return response.json();
112→}
113→
114→export function PairGatePage({ onPaired, serverId }: PairGatePageProps) {
115→  const prefill = getPairFromUrl();
116→  const [word, setWord] = useState(prefill?.word ?? "");
117→  const [number, setNumber] = useState(prefill?.number ?? "");
118→  const [error, setError] = useState<string | null>(null);
119→  const [isPending, setIsPending] = useState(false);
120→
121→  const numberRef = useRef<HTMLInputElement>(null);
122→  const formRef = useRef<HTMLFormElement>(null);
123→
124→  // Auto-submit if prefilled from QR code URL
125→  useEffect(() => {
126→    if (prefill?.word && prefill?.number) {
127→      submitCode(prefill.word, prefill.number);
128→    }
129→    // eslint-disable-next-line react-hooks/exhaustive-deps
130→  }, []);
131→
132→  const submitCode = useCallback(
133→    async (w: string, n: string) => {
134→      const code = `${w.toUpperCase()}-${n}`;
135→      setError(null);
136→      setIsPending(true);
137→
138→      const deviceName = navigator.userAgent.includes("Mobile") ? "Mobile Browser" : "Web Browser";
139→
140→      try {
141→        if (isRelayMode()) {
142→          // Relay mode: pair via one-shot WebSocket to relay
143→          const resolvedServerId = serverId || getServerIdFromUrl();
144→          if (!resolvedServerId) {
145→            setError("No server ID available for pairing");
146→            return;
147→          }
148→          const result = await pairViaRelay(resolvedServerId, code, deviceName);
149→          onPaired(result.token, deviceName);
150→        } else {
151→          // Direct mode: pair via HTTP POST to backend
152→          const data = await pairViaDirect(code, deviceName);
153→          onPaired(data.token, data.device?.name);
154→        }
155→      } catch (err) {
156→        setError(err instanceof Error ? err.message : "Could not connect to server");
157→      } finally {
158→        setIsPending(false);
159→      }
160→    },
161→    [onPaired, serverId]
162→  );
163→
164→  function handleSubmit(e: React.FormEvent) {
165→    e.preventDefault();
166→    if (!word.trim() || number.length !== 4) return;
167→    submitCode(word.trim(), number);
168→  }
169→
170→  function handleWordChange(e: React.ChangeEvent<HTMLInputElement>) {
171→    const val = e.target.value.replace(/[^a-zA-Z]/g, "").toUpperCase();
172→    setWord(val);
173→    setError(null);
174→    // Auto-advance to number field when word looks complete (2+ chars and user presses tab/enters)
175→  }
176→
177→  function handleWordKeyDown(e: React.KeyboardEvent) {
178→    if ((e.key === "-" || e.key === "Tab") && word.length >= 2) {
179→      e.preventDefault();
180→      numberRef.current?.focus();
181→    }
182→  }
183→
184→  function handleNumberChange(e: React.ChangeEvent<HTMLInputElement>) {
185→    const val = e.target.value.replace(/\D/g, "").slice(0, 4);
186→    setNumber(val);
187→    setError(null);
188→    // Auto-submit when 4 digits entered
189→    if (val.length === 4 && word.trim().length >= 2) {
190→      submitCode(word.trim(), val);
191→    }
192→  }
193→
194→  return (
195→    <div className="bg-background flex min-h-screen items-center justify-center p-4">
196→      <div className="w-full max-w-sm space-y-8">
197→        {/* Header */}
198→        <div className="text-center">
199→          <h1 className="text-2xl font-bold tracking-tight">Connect to OpenDevs</h1>
200→          <p className="text-muted-foreground mt-2 text-sm">
201→            Enter the pairing code from your desktop app to connect this device.
202→          </p>
203→        </div>
204→
205→        {/* Pairing form */}
206→        <form ref={formRef} onSubmit={handleSubmit} className="space-y-6">
207→          <div className="space-y-2">
208→            <Label className="text-sm font-medium">Pairing Code</Label>
209→            <div className="flex items-center gap-2">
210→              <Input
211→                type="text"
212→                placeholder="WORD"
213→                value={word}
214→                onChange={handleWordChange}
215→                onKeyDown={handleWordKeyDown}
216→                autoFocus
217→                autoComplete="off"
218→                autoCapitalize="characters"
219→                spellCheck={false}
220→                className="text-center font-mono text-lg tracking-wider uppercase"
221→                disabled={isPending}
222→              />
223→              <span className="text-muted-foreground text-xl font-bold">-</span>
224→              <Input
225→                ref={numberRef}
226→                type="text"
227→                inputMode="numeric"
228→                placeholder="0000"
229→                value={number}
230→                onChange={handleNumberChange}
231→                autoComplete="off"
232→                className="text-center font-mono text-lg tracking-wider"
233→                maxLength={4}
234→                disabled={isPending}
235→              />
236→            </div>
237→          </div>
238→
239→          {error && <p className="text-destructive text-center text-sm">{error}</p>}
240→
241→          <Button
242→            type="submit"
243→            className="w-full"
244→            disabled={isPending || word.length < 2 || number.length !== 4}
245→          >
246→            {isPending ? (
247→              <>
248→                <Loader2 className="mr-2 size-4 animate-spin" />
249→                Connecting...
250→              </>
251→            ) : (
252→              "Connect"
253→            )}
254→          </Button>
255→        </form>
256→
257→        {/* Help text */}
258→        <p className="text-muted-foreground text-center text-xs">
259→          Open Settings &gt; Remote Access in the OpenDevs desktop app to generate a pairing code.
260→        </p>
261→      </div>
262→    </div>
263→  );
264→}
