 1→// Remote access auth state management.
 2→// Checks if the current browser context requires token auth (non-Electron, non-localhost).
 3→// Stores and validates device tokens in localStorage.
 4→//
 5→// The signOut() function is the canonical way to log out from any module.
 6→// It clears localStorage AND dispatches a CustomEvent so any useAuth() listener
 7→// updates React state immediately (e.g., after an auth_failed WS frame).
 8→
 9→import { useState, useEffect, useCallback } from "react";
10→import { capabilities } from "@/platform/capabilities";
11→
12→const TOKEN_KEY = "opendevs_device_token";
13→const DEVICE_NAME_KEY = "opendevs_device_name";
14→const SIGNOUT_EVENT = "opendevs:signout";
15→
16→/** Whether this browser session needs remote auth (non-Electron + non-localhost). */
17→export function needsRemoteAuth(): boolean {
18→  if (capabilities.ipcInvoke) return false;
19→  const host = window.location.hostname;
20→  return host !== "localhost" && host !== "127.0.0.1" && host !== "::1";
21→}
22→
23→/** Get the stored device token (or null). */
24→export function getStoredToken(): string | null {
25→  try {
26→    return localStorage.getItem(TOKEN_KEY);
27→  } catch {
28→    return null;
29→  }
30→}
31→
32→/** Store a device token after successful pairing. */
33→export function storeToken(token: string, deviceName?: string): void {
34→  localStorage.setItem(TOKEN_KEY, token);
35→  if (deviceName) localStorage.setItem(DEVICE_NAME_KEY, deviceName);
36→}
37→
38→/** Clear stored token (logout). */
39→export function clearToken(): void {
40→  localStorage.removeItem(TOKEN_KEY);
41→  localStorage.removeItem(DEVICE_NAME_KEY);
42→}
43→
44→/**
45→ * Sign out: clears stored token AND dispatches a CustomEvent so any
46→ * useAuth() listener re-renders immediately. Safe to call from anywhere
47→ * (WS handlers, event listeners, non-React code). Supports multiple
48→ * listeners without mutable module state.
49→ */
50→export function signOut(): void {
51→  clearToken();
52→  window.dispatchEvent(new CustomEvent(SIGNOUT_EVENT));
53→}
54→
55→export interface AuthState {
56→  /** Whether auth check is still in progress. */
57→  isLoading: boolean;
58→  /** Whether the user is authenticated (or auth not required). */
59→  isAuthenticated: boolean;
60→  /** Set after successful pairing — triggers re-render. */
61→  onPaired: (token: string, deviceName?: string) => void;
62→}
63→
64→/**
65→ * Hook that manages remote auth state.
66→ * - Electron or localhost: always authenticated (no token needed).
67→ * - Remote browser: checks localStorage for a valid token.
68→ */
69→export function useAuth(): AuthState {
70→  const requiresAuth = needsRemoteAuth();
71→
72→  // Initialize state synchronously — no effect needed for initial check
73→  const [isAuthenticated, setIsAuthenticated] = useState(() => {
74→    if (!requiresAuth) return true;
75→    return !!getStoredToken();
76→  });
77→  const [isLoading] = useState(false);
78→
79→  // Listen for signOut events dispatched from any context (WS handlers, etc.)
80→  useEffect(() => {
81→    if (!requiresAuth) return;
82→
83→    const handler = () => setIsAuthenticated(false);
84→    window.addEventListener(SIGNOUT_EVENT, handler);
85→    return () => {
86→      window.removeEventListener(SIGNOUT_EVENT, handler);
87→    };
88→  }, [requiresAuth]);
89→
90→  const onPaired = useCallback((token: string, deviceName?: string) => {
91→    storeToken(token, deviceName);
92→    setIsAuthenticated(true);
93→  }, []);
94→
95→  return { isLoading, isAuthenticated, onPaired };
96→}
