 1→// TanStack Query hooks for remote access auth endpoints.
 2→
 3→import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
 4→import { AuthService } from "./auth.service";
 5→
 6→const authKeys = {
 7→  devices: ["auth", "devices"] as const,
 8→  relayStatus: ["auth", "relay-status"] as const,
 9→};
10→
11→/** Fetch paired devices. Polls every 10s when enabled. */
12→export function usePairedDevices(enabled: boolean) {
13→  return useQuery({
14→    queryKey: authKeys.devices,
15→    queryFn: () => AuthService.listDevices().then((r) => r.devices),
16→    enabled,
17→    refetchInterval: enabled ? 10_000 : false,
18→    staleTime: 5_000,
19→  });
20→}
21→
22→/** Generate a new pairing code (mutation). */
23→export function useGeneratePairCode() {
24→  return useMutation({
25→    mutationFn: () => AuthService.generatePairCode(),
26→  });
27→}
28→
29→/** Revoke a paired device. Invalidates the device list on success. */
30→export function useRevokeDevice() {
31→  const queryClient = useQueryClient();
32→  return useMutation({
33→    mutationFn: (id: string) => AuthService.revokeDevice(id),
34→    onSuccess: () => {
35→      queryClient.invalidateQueries({ queryKey: authKeys.devices });
36→    },
37→  });
38→}
39→
40→/** Fetch relay connection status. Polls every 5s when enabled. */
41→export function useRelayStatus(enabled: boolean) {
42→  return useQuery({
43→    queryKey: authKeys.relayStatus,
44→    queryFn: () => AuthService.getRelayStatus(),
45→    enabled,
46→    refetchInterval: enabled ? 5_000 : false,
47→    staleTime: 3_000,
48→  });
