 1→// Relay envelope protocol types.
 2→// Defines the framing between OpenDevs server <-> CF Durable Object relay <-> web clients.
 3→
 4→// ---- Server <-> Relay (tunnel) ----
 5→
 6→/** Frames sent from OpenDevs server to relay via tunnel WebSocket */
 7→export type ServerFrame =
 8→  | { type: "register"; serverId: string; relayToken: string; serverName?: string }
 9→  | { type: "data"; clientId: string; payload: string }
10→  | { type: "auth_response"; clientId: string; allowed: boolean; reason?: string }
11→  | { type: "pong" }
12→  // Pairing: desktop validated the code, returning the device token (or error)
13→  | { type: "pair_response"; pairId: string; success: true; deviceToken: string }
14→  | { type: "pair_response"; pairId: string; success: false; reason: string };
15→
16→/** Frames sent from relay to OpenDevs server via tunnel WebSocket */
17→export type RelayFrame =
18→  | { type: "registered" }
19→  | { type: "client_connected"; clientId: string; deviceToken: string }
20→  | { type: "client_disconnected"; clientId: string }
21→  | { type: "data"; clientId: string; payload: string }
22→  | { type: "ping" }
23→  | { type: "error"; message: string }
24→  // Pairing: web client wants to exchange a code for a device token
25→  | { type: "pair_request"; pairId: string; code: string; deviceName: string };
26→
27→// ---- Client <-> Relay ----
28→
29→/** First message a client sends after WebSocket connect */
30→export type ClientAuthFrame = { type: "authenticate"; token: string };
31→
32→/** Control frames sent from relay to client (auth + lifecycle) */
33→export type RelayClientFrame =
34→  | { type: "authenticated" }
35→  | { type: "auth_failed"; message: string }
36→  | { type: "server_offline"; serverName: string | null; serverDisconnectedAt: number }
37→  | { type: "server_reconnecting"; serverName: string | null; serverDisconnectedAt: number }
38→  | { type: "server_connected" }
39→  | { type: "error"; message: string };
40→
41→// ---- Pairer <-> Relay (one-shot /pair WebSocket) ----
42→
43→/** Frame sent from web portal to relay during pairing */
44→export type PairerRequestFrame = {
45→  type: "pair_request";
46→  code: string;
47→  deviceName: string;
48→};
49→
50→/** Control frames sent from relay to web portal pairer */
51→export type PairerResponseFrame =
52→  | { type: "pair_success"; token: string }
53→  | { type: "pair_failed"; message: string };
54→
55→// ---- Aliases (used by cloud-relay Durable Object) ----
56→
57→export type PairerFrame = PairerRequestFrame;
58→export type RelayPairerFrame = PairerResponseFrame;
