 33→import { WorkspaceStatusSchema } from "@shared/enums";
 34→import {
 35→  QUERY_RESOURCES,
 36→  REQUEST_RESOURCES,
 37→  MUTATION_NAMES,
 38→  COMMAND_NAMES,
 39→  type MutationName,
 40→  type CommandName,
 41→  type QueryResource,
 42→  type RequestResource,
 43→  type QServerFrame,
 44→} from "@shared/types/query-protocol";
 45→
 46→// ---- Subscription State ----
 47→
 48→type QueryParams = Record<string, unknown>;
 49→
 50→interface ResourceFrameInput {
 51→  id: string;
 52→  resource: string;
 53→  params: QueryParams;
 54→}
 55→
 56→interface UnsubscribeFrameInput {
 57→  id: string;
 58→}
 59→
 60→interface MutateFrameInput {
 61→  id: string;
 62→  action: string;
 63→  params: QueryParams;
 64→}
 65→
 66→interface CommandFrameInput {
 67→  id: string;
 68→  command: string;
 69→  params: QueryParams;
 70→}
 71→
 72→interface Sub {
 73→  id: string;
 74→  resource: QueryResource;
 75→  params: QueryParams;
 76→}
 77→
 78→/** Per-connection active subscriptions, keyed by client-assigned sub ID. */
 79→const subs = new Map<string, Map<string, Sub>>();
 80→
 81→/** For messages: track last seen seq per subscription for delta push.
 82→ *  Key: `${connectionId}:${subId}` → lastSeq */
 83→const messageCursors = new Map<string, number>();
 84→
 85→// ---- Public API ----
 86→
 87→/**
 88→ * Handle an incoming q:* frame from an authenticated connection.
 89→ * Registered as onQueryFrame in ws.service protocol handlers.
 90→ */
 91→export function handleFrame(connectionId: string, msg: QueryParams): void {
 92→  const type = typeof msg.type === "string" ? msg.type : "unknown";
 93→
 94→  try {
 95→    match(type)
 96→      .with("q:request", () => {
 97→        handleRequest(connectionId, parseResourceFrame(msg));
 98→      })
 99→      .with("q:subscribe", () => {
100→        handleSubscribe(connectionId, parseResourceFrame(msg));
101→      })
102→      .with("q:unsubscribe", () => {
103→        handleUnsubscribe(connectionId, parseUnsubscribeFrame(msg));
104→      })
105→      .with("q:mutate", () => {
106→        handleMutate(connectionId, parseMutateFrame(msg));
107→      })
108→      .with("q:command", () => {
109→        handleCommand(connectionId, parseCommandFrame(msg));
110→      })
111→      .with("q:tool_response", () => {
112→        handleToolResponse(msg);
113→      })
114→      .otherwise(() => {
115→        sendFrame(connectionId, {
116→          type: "q:error",
117→          id: getFrameId(msg),
118→          code: "UNKNOWN_FRAME",
119→          message: `Unknown query frame type: ${type}`,
120→        });
121→      });
122→  } catch (err) {
123→    sendFrame(connectionId, {
124→      type: "q:error",
125→      id: getFrameId(msg),
126→      code: "INVALID_FRAME",
127→      message: err instanceof Error ? err.message : "Invalid query frame",
128→    });
129→  }
130→}
131→
132→/** Remove all subscriptions for a connection (cleanup on disconnect). */
133→export function removeSubs(connectionId: string): void {
134→  const connSubs = subs.get(connectionId);
135→  if (connSubs) {
136→    for (const [subId, sub] of connSubs) {
137→      if (sub.resource === "messages") {
138→        messageCursors.delete(`${connectionId}:${subId}`);
139→      }
140→    }
141→    subs.delete(connectionId);
142→  }
143→}
144→
145→/** Optional context for targeted invalidation (e.g., which sessions changed). */
146→interface InvalidateContext {
147→  sessionIds?: string[];
148→}
149→
150→/**
151→ * Push-first invalidation: re-run queries for active subscribers and push
152→ * fresh snapshots or deltas.
153→ *
154→ * Messages use q:delta (cursor-based) instead of full snapshots.
155→ * When `ctx.sessionIds` is provided, workspace subscribers receive a targeted
156→ * q:delta (only the changed workspaces) instead of a full q:snapshot.
157→ */
158→export function invalidate(resources: QueryResource[], ctx?: InvalidateContext): void {
159→  if (resources.includes("stats")) {
160→    resetStatsCache();
161→  }
162→
163→  // Phase 1: Push fresh data to active subscribers
164→  for (const [connectionId, connSubs] of subs) {
165→    if (!getConnection(connectionId)) {
166→      removeSubs(connectionId);
167→      continue;
168→    }
169→
170→    for (const [subId, sub] of connSubs) {
171→      if (!resources.includes(sub.resource)) continue;
172→
173→      if (sub.resource === "messages") {
174→        // Messages: push delta (new messages since last cursor)
175→        pushMessageDelta(connectionId, subId, sub.params);
176→      } else if (sub.resource === "workspaces" && ctx?.sessionIds?.length) {
177→        // Workspaces with session context: try targeted delta
178→        try {
179→          const db = getDatabase();
180→          const stateFilter = readStringParam(sub.params, "state") ?? "ready,initializing";
181→          const allowedStates = new Set(stateFilter.split(",").map((s) => s.trim()));
182→          const changedWorkspaces = getWorkspacesBySessionIds(db, ctx.sessionIds).filter((ws) =>
183→            allowedStates.has(ws.state)
184→          );
185→          if (changedWorkspaces.length > 0) {
186→            const withPaths = changedWorkspaces.map((ws) => ({
187→              ...ws,
188→              workspace_path: computeWorkspacePath(ws),
189→            }));
190→            sendFrame(connectionId, {
191→              type: "q:delta",
192→              id: subId,
193→              upserted: withPaths,
194→            });
195→          } else {
196→            // Session IDs didn't match any workspaces — fall back to full snapshot
197→            const data = runQuery(sub.resource, sub.params);
198→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
199→          }
200→        } catch (err) {
201→          // Delta lookup failed — fall back to full snapshot
202→          console.error(`[QueryEngine] Workspace delta failed, falling back to snapshot:`, err);
203→          try {
204→            const data = runQuery(sub.resource, sub.params);
205→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
206→          } catch (snapErr) {
207→            console.error(`[QueryEngine] Snapshot fallback also failed:`, snapErr);
208→          }
209→        }
210→      } else if (sub.resource === "session" && ctx?.sessionIds?.length) {
211→        // Session with context: only push if this subscription's session is in the changed set
212→        const subscribedSessionId = readStringParam(sub.params, "sessionId");
213→        if (subscribedSessionId && ctx.sessionIds.includes(subscribedSessionId)) {
214→          try {
215→            const data = runQuery(sub.resource, sub.params);
216→            sendFrame(connectionId, { type: "q:snapshot", id: subId, data });
217→          } catch (err) {
218→            console.error(`[QueryEngine] Session snapshot push failed:`, err);
219→          }
220→        }
221→        // If session not in changed set, skip the push
222→      } else {
223→        // Other resources: push full snapshot
224→        try {
225→          const data = runQuery(sub.resource, sub.params);
226→          sendFrame(connectionId, {
227→            type: "q:snapshot",
228→            id: subId,
229→            data,
230→          });
231→        } catch (err) {
232→          console.error(`[QueryEngine] Snapshot push failed for ${sub.resource}:`, err);
233→        }
234→      }
235→    }
236→  }
237→}
