240→
241→async function handleRequest(connectionId: string, msg: ResourceFrameInput): Promise<void> {
242→  const { id, resource, params } = msg;
243→
244→  try {
245→    // Try subscribable resource first, then request-only resource
246→    if (isQueryResource(resource)) {
247→      const data = runQuery(resource, params);
248→      sendFrame(connectionId, { type: "q:response", id, data });
249→    } else if (isRequestResource(resource)) {
250→      const data = await runRequest(resource, params);

250→      const data = await runRequest(resource, params);
251→      sendFrame(connectionId, { type: "q:response", id, data });
252→    } else {
253→      throw new Error(`Unknown resource: ${resource}`);
254→    }
255→  } catch (err) {
256→    sendFrame(connectionId, {
257→      type: "q:error",
258→      id,
259→      code: "QUERY_ERROR",
260→      message: err instanceof Error ? err.message : "Query failed",
261→    });
262→  }
263→}
264→
265→function handleSubscribe(connectionId: string, msg: ResourceFrameInput): void {
266→  const { id, resource, params } = msg;
267→
268→  // Validate resource upfront — fail fast before running query
269→  const typedResource = toQueryResource(resource);
270→
271→  // Send initial snapshot — only register subscription if query succeeds
272→  // (avoids zombie subscriptions when runQuery throws on invalid params)
273→  try {
274→    const data = runQuery(typedResource, params);
275→
276→    // Get or create subscription map for this connection
277→    let connSubs = subs.get(connectionId);
278→    if (!connSubs) {
279→      connSubs = new Map();
280→      subs.set(connectionId, connSubs);
281→    }
282→
283→    // Store subscription by client-assigned ID (replaces if same ID reused on reconnect)
284→    connSubs.set(id, { id, resource: typedResource, params });
285→
286→    // For messages: initialize cursor to current max seq
287→    if (typedResource === "messages") {
288→      const sessionId = readStringParam(params, "sessionId");
289→      const cursorKey = `${connectionId}:${id}`;
290→      if (sessionId) {
291→        try {
292→          const db = getDatabase();
293→          messageCursors.set(cursorKey, getMaxMessageSeq(db, sessionId));
294→        } catch {
295→          messageCursors.set(cursorKey, 0);
296→        }
297→      }
298→    }
299→
300→    sendFrame(connectionId, { type: "q:snapshot", id, data });
301→  } catch (err) {
302→    sendFrame(connectionId, {
303→      type: "q:error",
304→      id,
305→      code: "SUBSCRIBE_ERROR",
306→      message: err instanceof Error ? err.message : "Subscribe failed",
307→    });
308→  }
309→}
310→
311→function handleUnsubscribe(connectionId: string, msg: UnsubscribeFrameInput): void {
312→  const { id } = msg;
313→
314→  const connSubs = subs.get(connectionId);
315→  if (!connSubs) return;
316→
317→  const sub = connSubs.get(id);
318→  if (sub) {
319→    // Clean up message cursor
320→    if (sub.resource === "messages") {
321→      messageCursors.delete(`${connectionId}:${id}`);
322→    }
323→    connSubs.delete(id);
324→    if (connSubs.size === 0) subs.delete(connectionId);
325→  }
326→}
