328→async function handleMutate(connectionId: string, msg: MutateFrameInput): Promise<void> {
329→  const { id, action, params } = msg;
330→
331→  try {
332→    const result = await runMutation(action, params);
333→    sendFrame(connectionId, {
334→      type: "q:mutate_result",
