  1→// backend/src/services/remote-auth.service.ts
  2→// Core auth logic for remote access: pairing codes, device tokens, rate limiting.
  3→// Pairing codes are ephemeral (in-memory), device tokens are persistent (DB).
  4→
  5→import { randomBytes, randomInt, createHash } from "crypto";
