 23→function timeAgo(dateStr: string): string {
 24→  const diff = Date.now() - new Date(dateStr).getTime();
 25→  const minutes = Math.floor(diff / 60_000);
 26→  if (minutes < 1) return "just now";
 27→  if (minutes < 60) return `${minutes}m ago`;
 28→  const hours = Math.floor(minutes / 60);
 29→  if (hours < 24) return `${hours}h ago`;
 30→  const days = Math.floor(hours / 24);
 31→  return `${days}d ago`;
 32→}
 33→
 34→function getDeviceIcon(ua: string | null) {
 35→  if (!ua) return Monitor;
 36→  const lower = ua.toLowerCase();
 37→  if (lower.includes("mobile") || lower.includes("iphone") || lower.includes("android")) {
 38→    return Smartphone;
 39→  }
 40→  return Monitor;
 41→}
