 1→// Frontend API service for remote access auth endpoints.
 2→// generatePairCode stays as HTTP — it's a pre-auth localhost-only endpoint.
 3→
 4→import { apiClient } from "@/shared/api/client";
 5→import { sendRequest, sendMutate } from "@/platform/ws";
 6→
 7→export interface PairedDevice {
 8→  id: string;
 9→  name: string;
10→  ip_address: string | null;
11→  user_agent: string | null;
12→  last_seen_at: string;
13→  created_at: string;
14→}
15→
16→export interface PairCodeResponse {
17→  code: string;
18→  expires_in_seconds: number;
19→}
20→
21→export const AuthService = {
22→  // Pre-auth endpoint — must stay as HTTP (no WS connection yet during pairing)
23→  generatePairCode: (): Promise<PairCodeResponse> =>
24→    apiClient.post<PairCodeResponse>("/remote-auth/generate-pair-code"),
25→
26→  listDevices: (): Promise<{ devices: PairedDevice[] }> =>
27→    sendRequest<{ devices: PairedDevice[] }>("pairedDevices"),
28→
29→  revokeDevice: async (id: string): Promise<{ success: boolean }> => {
30→    const result = await sendMutate<{ success: boolean }>("revokeDevice", { deviceId: id });
31→    if (!result.success) throw new Error(result.error || "Failed to revoke device");
32→    return result.data ?? { success: true };
33→  },
34→
35→  getRelayStatus: (): Promise<RelayStatus> => sendRequest<RelayStatus>("relayStatus"),
36→};
37→
38→export interface RelayStatus {
39→  connected: boolean;
40→  clients: number;
41→  serverId: string | null;
42→  relayUrl: string | null;
43→}
