// Browser gate page for remote device pairing.
// Shown when a non-localhost browser accesses OpenDevs without a valid token.
// Provides a single text input to enter a two-word connection code (e.g. "SOFT TIGER").
//
// In relay mode (web-production), pairing happens through a one-shot WebSocket
// to the relay's /pair endpoint. In direct mode (web-dev with remote host),
// pairing POSTs to the backend's /api/remote-auth/pair endpoint.

import { useState, useRef, useEffect, useCallback } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Loader2 } from "lucide-react";
import { isRelayMode, RELAY_BASE_URL } from "@/shared/config/backend.config";

interface PairGatePageProps {
  onPaired: (token: string, deviceName?: string) => void;
  /** Server ID for relay mode pairing. Extracted from route params by ServerLayout. */
  serverId?: string;
}

/**
 * Extract a two-word code from a URL query param or a pasted URL.
 * Handles ?pair=SOFT+TIGER, ?pair=SOFT%20TIGER, and ?pair=SOFT-TIGER.
 */
function getPairFromUrl(): string | null {
  const params = new URLSearchParams(window.location.search);
  const pair = params.get("pair");
  if (!pair) return null;
  // Normalize: treat +, -, _ as spaces, collapse whitespace, uppercase
  const normalized = pair
    .replace(/[-_+]/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .toUpperCase();
  // Must be exactly two words
  const parts = normalized.split(" ");
  if (parts.length === 2 && parts[0].length >= 2 && parts[1].length >= 2) {
    return normalized;
  }
  return null;
}

/**
 * Extract a pair code from a pasted URL string.
 * E.g. "https://app.rundeus.com/connect/abc?pair=SOFT+TIGER" -> "SOFT TIGER"
 */
function extractCodeFromPastedUrl(text: string): string | null {
  try {
    const url = new URL(text.trim());
    const pair = url.searchParams.get("pair");
    if (!pair) return null;
    const normalized = pair
      .replace(/[-_+]/g, " ")
      .replace(/\s+/g, " ")
      .trim()
      .toUpperCase();
    const parts = normalized.split(" ");
    if (parts.length === 2 && parts[0].length >= 2 && parts[1].length >= 2) {
      return normalized;
    }
  } catch {
    // Not a valid URL — that's fine, treat as raw text
  }
  return null;
}

/** Check if a string looks like a valid two-word code. */
function isValidTwoWordCode(value: string): boolean {
  const parts = value.trim().split(/\s+/);
  return parts.length === 2 && parts.every((p) => /^[A-Z]{2,}$/.test(p));
}

/** Extract serverId from the current URL pathname (/s/{serverId}/...). */
function getServerIdFromUrl(): string | null {
  const match = window.location.pathname.match(/^\/s\/([^/]+)/);
  return match ? match[1] : null;
}

/**
 * Pair via the relay's one-shot /pair WebSocket endpoint.
 * Opens a WS to wss://relay.rundeus.com/api/servers/{serverId}/pair,
 * sends the pairing code, and waits for pair_success or pair_failed.
 */
function pairViaRelay(
  serverId: string,
  code: string,
  deviceName: string
): Promise<{ token: string }> {
  return new Promise((resolve, reject) => {
    const url = `${RELAY_BASE_URL}/api/servers/${encodeURIComponent(serverId)}/pair`;
    const ws = new WebSocket(url);
    const timeout = setTimeout(() => {
      ws.close();
      reject(new Error("Pairing timed out"));
    }, 30_000);

    ws.onopen = () => {
      ws.send(JSON.stringify({ type: "pair_request", code, deviceName }));
    };

    ws.onmessage = (evt) => {
      clearTimeout(timeout);
      try {
        const msg = JSON.parse(evt.data as string);
        if (msg.type === "pair_success" && msg.token) {
          resolve({ token: msg.token });
        } else if (msg.type === "pair_failed") {
          reject(new Error(msg.message || "Pairing failed"));
        } else {
          reject(new Error("Unexpected response from relay"));
        }
      } catch {
        reject(new Error("Invalid response from relay"));
      }
      ws.close();
    };

    ws.onerror = () => {
      clearTimeout(timeout);
      reject(new Error("Could not connect to relay"));
    };

    ws.onclose = (evt) => {
      clearTimeout(timeout);
      // If not resolved/rejected yet, treat as error
      if (evt.code !== 1000) {
        reject(new Error("Connection closed unexpectedly"));
      }
    };
  });
}

/**
 * Pair via direct HTTP POST to the backend (non-relay mode).
 */
async function pairViaDirect(
  code: string,
  deviceName: string
): Promise<{ token: string; device?: { name: string } }> {
  const baseUrl = `${window.location.protocol}//${window.location.host}`;
  const response = await fetch(`${baseUrl}/api/remote-auth/pair`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ code, deviceName }),
  });

  if (!response.ok) {
    const data = await response.json().catch(() => null);
    throw new Error(data?.error ?? "Invalid connection code");
  }

  return response.json();
}

export function PairGatePage({ onPaired, serverId }: PairGatePageProps) {
  const prefill = getPairFromUrl();
  const [code, setCode] = useState(prefill ?? "");
  const [error, setError] = useState<string | null>(null);
  const [isPending, setIsPending] = useState(false);

  const autoSubmitTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Auto-submit if prefilled from QR code URL
  useEffect(() => {
    if (prefill) {
      submitCode(prefill);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const submitCode = useCallback(
    async (rawCode: string) => {
      const normalized = rawCode.trim().toUpperCase();
      if (!isValidTwoWordCode(normalized)) return;

      setError(null);
      setIsPending(true);

      const deviceName = navigator.userAgent.includes("Mobile") ? "Mobile Browser" : "Web Browser";

      try {
        if (isRelayMode()) {
          const resolvedServerId = serverId || getServerIdFromUrl();
          if (!resolvedServerId) {
            setError("No server ID available for pairing");
            return;
          }
          const result = await pairViaRelay(resolvedServerId, normalized, deviceName);
          onPaired(result.token, deviceName);
        } else {
          const data = await pairViaDirect(normalized, deviceName);
          onPaired(data.token, data.device?.name);
        }
      } catch (err) {
        setError(err instanceof Error ? err.message : "Could not connect to server");
      } finally {
        setIsPending(false);
      }
    },
    [onPaired, serverId]
  );

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    submitCode(code);
  }

  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    const val = e.target.value.toUpperCase();
    setCode(val);
    setError(null);
  }

  function handlePaste(e: React.ClipboardEvent<HTMLInputElement>) {
    const pasted = e.clipboardData.getData("text");

    // Smart paste: extract code from a full URL
    const extracted = extractCodeFromPastedUrl(pasted);
    if (extracted) {
      e.preventDefault();
      setCode(extracted);
      setError(null);

      // Auto-submit with debounce on valid paste
      if (autoSubmitTimer.current) clearTimeout(autoSubmitTimer.current);
      autoSubmitTimer.current = setTimeout(() => {
        submitCode(extracted);
      }, 300);
      return;
    }

    // Smart paste: normalize raw pasted code (e.g. "soft-tiger")
    const normalized = pasted
      .replace(/[-_+]/g, " ")
      .replace(/\s+/g, " ")
      .trim()
      .toUpperCase();
    if (isValidTwoWordCode(normalized)) {
      e.preventDefault();
      setCode(normalized);
      setError(null);

      if (autoSubmitTimer.current) clearTimeout(autoSubmitTimer.current);
      autoSubmitTimer.current = setTimeout(() => {
        submitCode(normalized);
      }, 300);
    }
  }

  const codeIsValid = isValidTwoWordCode(code);

  return (
    <div className="bg-background flex min-h-screen items-center justify-center p-4">
      <div className="w-full max-w-sm space-y-8">
        {/* Header */}
        <div className="text-center">
          <h1 className="text-2xl font-bold tracking-tight">Connect to OpenDevs</h1>
          <p className="text-muted-foreground mt-2 text-sm">
            Enter the connection code from your desktop app.
          </p>
        </div>

        {/* Connection code form */}
        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <Input
              type="text"
              placeholder="ENTER CODE"
              value={code}
              onChange={handleChange}
              onPaste={handlePaste}
              autoFocus
              autoComplete="off"
              autoCapitalize="characters"
              spellCheck={false}
              className="text-center font-mono text-lg tracking-wider uppercase"
              disabled={isPending}
            />
          </div>

          {error && <p className="text-destructive text-center text-sm">{error}</p>}

          <Button type="submit" className="w-full" disabled={isPending || !codeIsValid}>
            {isPending ? (
              <>
                <Loader2 className="mr-2 size-4 animate-spin" />
                Connecting...
              </>
            ) : (
              "Connect"
            )}
          </Button>
        </form>
      </div>
    </div>
  );
}

