 91→const activeCodes = new Map<string, PairingCode>();
 92→const rateLimits = new Map<string, RateLimitEntry>();
 93→
 94→// ---- Pairing Codes ----
 95→
 96→/** Generate a two-word pairing code (e.g. "SOFT TIGER"). Returns the code string and its expiry. */
 97→export function generatePairCode(): { code: string; expiresAt: number } {
 98→  // Evict expired codes first
 99→  const now = Date.now();
100→  for (const [key, entry] of activeCodes) {
101→    if (entry.expiresAt <= now) activeCodes.delete(key);
102→  }
103→
104→  // Enforce max active codes
105→  if (activeCodes.size >= MAX_ACTIVE_CODES) {
106→    // Evict oldest
107→    let oldestKey: string | null = null;
108→    let oldestTime = Infinity;
109→    for (const [key, entry] of activeCodes) {
110→      if (entry.createdAt < oldestTime) {
111→        oldestTime = entry.createdAt;
112→        oldestKey = key;
113→      }
114→    }
115→    if (oldestKey) activeCodes.delete(oldestKey);
116→  }
117→
118→  // Pick two different words
119→  const idx1 = randomInt(WORD_LIST.length);
120→  let idx2 = randomInt(WORD_LIST.length - 1);
121→  if (idx2 >= idx1) idx2 += 1;
122→
123→  const code = `${WORD_LIST[idx1]} ${WORD_LIST[idx2]}`;
124→  const expiresAt = now + CODE_TTL_MS;
125→
126→  activeCodes.set(code, { code, createdAt: now, expiresAt });
127→  return { code, expiresAt };
128→}
129→
130→/**
131→ * Normalize a pairing code input to canonical form (e.g. "SOFT TIGER").
132→ * Accepts dashes, underscores, plus signs, and extra whitespace as word separators.
133→ */
134→function normalizePairCode(raw: string): string {
135→  return raw
136→    .trim()
137→    .replace(/[-_+]/g, " ")   // treat dashes, underscores, plus as spaces
138→    .replace(/\s+/g, " ")     // collapse multiple spaces
139→    .toUpperCase();
140→}
141→
142→/** Validate and consume a pairing code. Returns true if valid (one-time use). */
143→export function validatePairCode(code: string): boolean {
144→  const normalized = normalizePairCode(code);
145→  const entry = activeCodes.get(normalized);
146→  if (!entry) {
147→    console.log(`[Auth] Code "${normalized}" not found. Active codes: ${activeCodes.size}`);
148→    return false;
149→  }
150→  if (entry.expiresAt <= Date.now()) {
151→    activeCodes.delete(normalized);
152→    return false;
153→  }
154→  // One-time use — delete immediately
155→  activeCodes.delete(normalized);
156→  return true;
157→}
158→
159→/** Get number of active (non-expired) pairing codes. */
160→export function getActiveCodeCount(): number {
161→  const now = Date.now();
162→  for (const [key, entry] of activeCodes) {
163→    if (entry.expiresAt <= now) activeCodes.delete(key);
164→  }
165→  return activeCodes.size;
166→}
