  "CORE",    "CORK",    "CORN",    "COST",    "CREW",    "CROP",    "CROW",
  "CUBE",    "CURE",    "CURL",    "DARK",    "DASH",    "DATA",    "DATE",
  "DAWN",    "DEAL",    "DEAR",    "DECK",    "DEEP",    "DEER",    "DEMO",
  "DENY",    "DESK",    "DIAL",    "DIET",    "DIRT",    "DISC",    "DISH",
  "DOCK",    "DOME",    "DONE",    "DOOR",    "DOSE",    "DOWN",    "DRAW",
  "DROP",    "DRUM",    "DUAL",    "DUNE",    "DUST",    "DUTY",    "EACH",
  "EARN",    "EASE",    "EAST",    "EASY",    "EDGE",    "EDIT",    "ELSE",
  "EPIC",    "EVEN",    "EVER",    "EVIL",    "EXAM",    "FACE",    "FACT",
  "FADE",    "FAIL",    "FAIR",    "FAKE",    "FALL",    "FAME",    "FARM",
  "FAST",    "FATE",    "FAWN",    "FEED",    "FEEL",    "FELT",    "FERN",
  "FILM",    "FIND",    "FINE",    "FIRE",    "FIRM",    "FISH",    "FLAG",
  "FLAT",    "FLED",    "FLIP",    "FLOW",    "FOAM",    "FOLD",    "FOLK",
  "FOND",    "FONT",    "FOOD",    "FOOL",    "FORD",    "FORK",    "FORM",
  "FORT",    "FOUL",    "FREE",    "FROM",    "FUEL",    "FULL",    "FUND",
  "FURY",    "FUSE",    "GAIN",    "GALE",    "GAME",    "GANG",    "GATE",
  "GAVE",    "GEAR",    "GIFT",    "GIRL",    "GLAD",    "GLOW",    "GLUE",
