  "HEAD",    "HEAL",    "HEAP",    "HEAT",    "HELD",    "HELM",    "HELP",
  "HERB",    "HERO",    "HIGH",    "HIKE",    "HILL",    "HINT",    "HIRE",
  "HIVE",    "HOLD",    "HOLE",    "HOME",    "HOOD",    "HOOK",    "HOPE",
  "HORN",    "HOST",    "HUGE",    "HULL",    "HUNG",    "HUNT",    "HURT",
  "ICON",    "IDEA",    "INCH",    "INTO",    "IRON",    "ISLE",    "ITEM",
  "JACK",    "JADE",    "JAIL",    "JAVA",    "JAZZ",    "JEAN",    "JEST",
  "JOBS",    "JOIN",    "JOKE",    "JUMP",    "JUNE",    "JURY",    "JUST",
