 72→  connected: boolean;
 73→  clients: number;
 74→}) {
 75→  return (
 76→    <div className="border-border/60 bg-muted/30 space-y-3 rounded-xl border px-4 py-4">
 77→      {/* Status line */}
 78→      <div className="flex items-center gap-2.5">
 79→        <span
 80→          className={`size-[7px] shrink-0 rounded-full ${
 81→            connected ? "bg-emerald-500 shadow-[0_0_6px_rgba(16,185,129,0.35)]" : "bg-red-400"
 82→          }`}
 83→        />
 84→        <span className="text-muted-foreground text-xs font-medium">
 85→          {connected ? "Connected" : "Connecting..."}
 86→        </span>
 87→        {connected && clients > 0 && (
 88→          <span className="text-muted-foreground/70 text-[11px]">
 89→            &middot; {clients} {clients === 1 ? "device" : "devices"} online
 90→          </span>
 91→        )}
 92→      </div>
 93→
 94→      {/* URL + actions */}
 95→      <div className="flex items-center gap-2">
 96→        <p className="min-w-0 flex-1 truncate font-mono text-sm leading-relaxed">{url}</p>
 97→        <Button
 98→          variant="ghost"
 99→          size="icon"
100→          className="size-7 shrink-0"
101→          onClick={() => {
102→            navigator.clipboard.writeText(url);
103→            toast.success("URL copied");
104→          }}
105→          title="Copy URL"
106→        >
107→          <Copy className="size-3.5" />
108→        </Button>
109→      </div>
110→    </div>
111→  );
112→}
113→
114→/**
115→ * Connect Device Dialog -- shows QR code + code + countdown.
116→ * Eagerly generates a code on open.
117→ */
118→function ConnectDeviceDialog({
119→  open,
120→  onOpenChange,
121→  accessUrl,
122→  devices,
123→}: {
124→  open: boolean;
125→  onOpenChange: (open: boolean) => void;
126→  accessUrl: string | null;
127→  devices: PairedDevice[];
128→}) {
129→  const generateCodeMutation = useGeneratePairCode();
130→  const [pairCode, setPairCode] = useState<string | null>(null);
131→  const [codeExpiresAt, setCodeExpiresAt] = useState(0);
132→  const [countdown, setCountdown] = useState(0);
133→  const [prevDeviceCount, setPrevDeviceCount] = useState(devices.length);
134→  const [showSuccess, setShowSuccess] = useState(false);
135→
136→  // Eagerly generate code when dialog opens
137→  useEffect(() => {
138→    if (open && !pairCode && !generateCodeMutation.isPending) {
139→      generateCodeMutation
140→        .mutateAsync()
141→        .then((result) => {
142→          setPairCode(result.code);
143→          setCodeExpiresAt(Date.now() + result.expires_in_seconds * 1000);
144→        })
145→        .catch((error) => {
146→          toast.error(`Failed to generate code: ${getErrorMessage(error)}`);
147→        });
148→    }
149→    // Reset state when closing
150→    if (!open) {
151→      setPairCode(null);
152→      setCodeExpiresAt(0);
153→      setCountdown(0);
154→      setShowSuccess(false);
155→    }
156→    // eslint-disable-next-line react-hooks/exhaustive-deps
157→  }, [open]);
158→
159→  // Countdown timer
160→  useEffect(() => {
161→    if (!pairCode || codeExpiresAt <= 0) return;
162→    const tick = () => {
163→      const remaining = Math.max(0, Math.ceil((codeExpiresAt - Date.now()) / 1000));
164→      setCountdown(remaining);
165→      if (remaining <= 0) {
166→        setPairCode(null);
167→        setCodeExpiresAt(0);
168→      }
169→    };
170→    tick();
171→    const interval = setInterval(tick, 1000);
172→    return () => clearInterval(interval);
173→  }, [pairCode, codeExpiresAt]);
174→
175→  // Detect successful pairing via device count change
176→  useEffect(() => {
177→    if (open && devices.length > prevDeviceCount) {
178→      setShowSuccess(true);
179→      // Auto-close after 2 seconds
180→      const timer = setTimeout(() => {
181→        onOpenChange(false);
182→      }, 2000);
183→      return () => clearTimeout(timer);
184→    }
185→    setPrevDeviceCount(devices.length);
186→    return undefined;
187→    // eslint-disable-next-line react-hooks/exhaustive-deps
188→  }, [devices.length, open]);
189→
190→  const pairUrl = accessUrl && pairCode ? buildPairUrl(accessUrl, pairCode) : null;
191→  const minutes = Math.floor(countdown / 60);
192→  const isExpiringSoon = countdown > 0 && countdown < 120; // < 2 minutes
193→
194→  function handleCopyCode() {
195→    if (!pairCode) return;
196→    navigator.clipboard.writeText(pairCode);
197→    toast.success("Code copied");
198→  }
199→
200→  function handleCopyLink() {
201→    if (!pairUrl) return;
202→    navigator.clipboard.writeText(pairUrl);
203→    toast.success("Link copied");
204→  }
205→
206→  return (
207→    <Dialog open={open} onOpenChange={onOpenChange}>
208→      <DialogContent className="sm:max-w-md">
209→        {showSuccess ? (
210→          /* Success state */
211→          <div className="flex flex-col items-center gap-4 py-8">
212→            <div className="bg-emerald-500/10 flex size-16 items-center justify-center rounded-full">
213→              <Check className="size-8 text-emerald-500" />
214→            </div>
215→            <div className="text-center">
216→              <DialogTitle className="text-lg font-semibold">Device Connected</DialogTitle>
217→              <DialogDescription className="text-muted-foreground mt-1 text-sm">
218→                Your device has been connected successfully.
219→              </DialogDescription>
220→            </div>
221→          </div>
222→        ) : (
223→          /* Code + QR state */
224→          <>
225→            <DialogHeader className="text-center">
226→              <DialogTitle>Connect a Device</DialogTitle>
227→              <DialogDescription>
228→                Scan the QR code or enter the code on your other device.
229→              </DialogDescription>
230→            </DialogHeader>
231→
232→            <div className="flex flex-col items-center gap-5 pt-2">
233→              {/* QR Code -- hero element */}
234→              {pairUrl ? (
235→                <div className="bg-white rounded-xl p-3">
236→                  <QRCodeSVG value={pairUrl} size={180} level="M" />
237→                </div>
238→              ) : (
239→                <div className="bg-muted/40 flex size-[204px] items-center justify-center rounded-xl">
240→                  <span className="text-muted-foreground text-sm">Generating...</span>
241→                </div>
242→              )}
243→
244→              {/* Code display */}
245→              {pairCode ? (
246→                <p className="font-mono text-2xl font-bold tracking-wide">{pairCode}</p>
247→              ) : (
248→                <div className="bg-muted/40 h-8 w-40 animate-pulse rounded" />
249→              )}
250→
251→              {/* Action buttons */}
252→              <div className="flex gap-2">
253→                <Button
254→                  variant="outline"
255→                  size="sm"
256→                  onClick={handleCopyCode}
257→                  disabled={!pairCode}
258→                >
259→                  <Copy className="mr-1.5 size-3.5" />
260→                  Copy Code
261→                </Button>
262→                <Button
263→                  variant="outline"
264→                  size="sm"
265→                  onClick={handleCopyLink}
266→                  disabled={!pairUrl}
267→                >
268→                  <Link2 className="mr-1.5 size-3.5" />
269→                  Copy Link
270→                </Button>
271→              </div>
272→
273→              {/* Countdown */}
274→              {countdown > 0 && (
275→                <p
276→                  className={`text-xs ${
277→                    isExpiringSoon ? "text-amber-500" : "text-muted-foreground"
278→                  }`}
279→                >
280→                  Expires in {minutes} {minutes === 1 ? "minute" : "minutes"}
281→                </p>
282→              )}
283→            </div>
284→          </>
285→        )}
286→      </DialogContent>
287→    </Dialog>
288→  );
289→}
290→
291→/**
292→ * Connected devices list with remove action per device.
293→ */
294→function DevicesList({
295→  devices,
296→  onRemove,
297→  isRemoving,
298→}: {
299→  devices: PairedDevice[];
300→  onRemove: (device: PairedDevice) => void;
301→  isRemoving: boolean;
302→}) {
303→  if (devices.length === 0) {
304→    return <p className="text-muted-foreground py-0.5 text-sm">No devices connected yet.</p>;
305→  }
306→
307→  return (
308→    <div className="space-y-1.5">
309→      {devices.map((device) => {
310→        const DeviceIcon = getDeviceIcon(device.user_agent);
311→        return (
312→          <div
313→            key={device.id}
314→            className="bg-muted/30 flex items-center justify-between rounded-lg px-4 py-2.5"
315→          >
316→            <div className="flex items-center gap-3">
317→              <DeviceIcon className="text-muted-foreground size-4 shrink-0" />
318→              <div>
319→                <p className="text-sm font-medium">{device.name}</p>
320→                <p className="text-muted-foreground text-xs">
321→                  {timeAgo(device.last_seen_at)}
322→                  {device.ip_address ? ` \u00b7 ${device.ip_address}` : ""}
323→                </p>
324→              </div>
325→            </div>
326→            <Button
327→              variant="ghost"
328→              size="icon"
329→              className="text-muted-foreground hover:text-destructive size-7"
330→              onClick={() => onRemove(device)}
331→              disabled={isRemoving}
332→              title={`Remove ${device.name}`}
333→            >
334→              <Trash2 className="size-3.5" />
335→            </Button>
336→          </div>
337→        );
338→      })}
339→    </div>
340→  );
341→}
342→
343→// ---------------------------------------------------------------------------
344→// Main Section
345→// ---------------------------------------------------------------------------
346→
347→/**
348→ * Unified Access settings section.
349→ *
350→ * Hierarchy:
351→ *   1. Toggle + hero portal card (URL, status, copy)
352→ *   2. "+ Connect a Device" button that opens a dialog with QR + code
353→ *   3. Connected devices list
354→ */
355→export function AccessSection({ settings, saveSetting }: SettingsSectionProps) {
356→  const enabled = settings.remote_access_enabled === true;
357→
358→  // Remote access queries -- only active when enabled
359→  const devicesQuery = usePairedDevices(enabled);
360→  const relayQuery = useRelayStatus(enabled);
361→  const revokeDeviceMutation = useRevokeDevice();
362→
363→  // Dialog state
364→  const [dialogOpen, setDialogOpen] = useState(false);
365→
366→  // -- Handlers --
367→
368→  const handleToggle = useCallback(
369→    async (on: boolean) => {
370→      const ok = await saveSetting("remote_access_enabled", on);
371→      if (ok) {
372→        toast.success(on ? "Remote access enabled" : "Remote access disabled");
373→      }
374→    },
375→    [saveSetting]
376→  );
377→
378→  async function handleRemoveDevice(device: PairedDevice) {
379→    try {
380→      await revokeDeviceMutation.mutateAsync(device.id);
381→      toast.success(`Removed "${device.name}"`);
382→    } catch (error) {
383→      toast.error(`Failed to remove device: ${getErrorMessage(error)}`);
384→    }
385→  }
386→
387→  // -- Derived values --
388→
389→  const relayStatus = relayQuery.data;
390→  const devices = devicesQuery.data ?? [];
391→
392→  // Derive web app URL from relay WebSocket URL
393→  // wss://relay.rundeus.com -> https://app.rundeus.com/connect/{serverId}
394→  const accessUrl = (() => {
395→    if (!relayStatus?.relayUrl || !relayStatus.serverId) return null;
396→    try {
397→      const url = new URL(relayStatus.relayUrl);
398→      const host = url.hostname;
399→      const domain = host.replace(/^relay\./, "app.");
400→      return `https://${domain}/connect/${relayStatus.serverId}`;
401→    } catch {
402→      return null;
403→    }
404→  })();
405→
406→  // -- Render --
407→
408→  return (
409→    <div className="space-y-6">
410→      {/* Header */}
411→      <div>
412→        <h3 className="text-base font-semibold">Connect</h3>
413→        <p className="text-muted-foreground mt-1 text-sm">
414→          Access Deus from your phone or another browser.
415→        </p>
416→      </div>
417→
418→      {/* Master toggle */}
419→      <div className="flex items-center justify-between">
420→        <div>
421→          <Label htmlFor="remote-access-toggle" className="text-sm">
422→            Enable remote access
423→          </Label>
424→          <p className="text-muted-foreground text-xs">
425→            Allow other devices to connect to this machine.
426→          </p>
427→        </div>
428→        <Switch id="remote-access-toggle" checked={enabled} onCheckedChange={handleToggle} />
429→      </div>
430→
431→      {/* ----- Everything below is gated on the toggle ----- */}
432→
433→      {enabled && (
434→        <>
435→          {/* Portal card -- hero element: URL + status */}
436→          {accessUrl && relayStatus && (
437→            <PortalCard
438→              url={accessUrl}
439→              connected={relayStatus.connected}
440→              clients={relayStatus.clients}
441→            />
442→          )}
443→
444→          {/* Disconnected state without URL */}
445→          {relayStatus && !accessUrl && (
446→            <div className="bg-muted/30 flex items-center gap-2.5 rounded-lg px-4 py-3">
447→              <span className="size-[7px] shrink-0 rounded-full bg-amber-400" />
448→              <span className="text-muted-foreground text-sm">
449→                {relayStatus.connected
450→                  ? "Connected — waiting for configuration..."
451→                  : "Connecting..."}
452→              </span>
453→            </div>
454→          )}
455→
456→          <Separator />
457→
458→          {/* Connect a Device button */}
459→          <div className="space-y-3">
460→            <Button variant="outline" size="sm" onClick={() => setDialogOpen(true)}>
461→              <Plus className="mr-1.5 size-3.5" />
462→              Connect a Device
463→            </Button>
464→          </div>
465→
466→          {/* Connect Device Dialog */}
467→          <ConnectDeviceDialog
468→            open={dialogOpen}
469→            onOpenChange={setDialogOpen}
470→            accessUrl={accessUrl}
471→            devices={devices}
472→          />
473→
474→          <Separator />
475→
476→          {/* Connected devices */}
477→          <div className="space-y-3">
478→            <div className="flex items-center gap-2">
479→              <h4 className="text-sm font-medium">Connected Devices</h4>
480→              {devices.length > 0 && (
481→                <Badge variant="secondary" className="text-[11px]">
482→                  {devices.length}
483→                </Badge>
484→              )}
485→            </div>
486→            <DevicesList
487→              devices={devices}
488→              onRemove={handleRemoveDevice}
489→              isRemoving={revokeDeviceMutation.isPending}
490→            />
491→          </div>
492→        </>
493→      )}
494→    </div>
495→  );
496→}
