343→// ---------------------------------------------------------------------------
344→// Main Section
345→// ---------------------------------------------------------------------------
346→
347→/**
348→ * Unified Access settings section.
349→ *
350→ * Hierarchy:
351→ *   1. Toggle + hero portal card (URL, status, copy)
352→ *   2. "+ Connect a Device" button that opens a dialog with QR + code
353→ *   3. Connected devices list
354→ */
355→export function AccessSection({ settings, saveSetting }: SettingsSectionProps) {
356→  const enabled = settings.remote_access_enabled === true;
357→
358→  // Remote access queries -- only active when enabled
359→  const devicesQuery = usePairedDevices(enabled);
360→  const relayQuery = useRelayStatus(enabled);
361→  const revokeDeviceMutation = useRevokeDevice();
362→
363→  // Dialog state
364→  const [dialogOpen, setDialogOpen] = useState(false);
365→
366→  // -- Handlers --
367→
368→  const handleToggle = useCallback(
369→    async (on: boolean) => {
370→      const ok = await saveSetting("remote_access_enabled", on);
371→      if (ok) {
372→        toast.success(on ? "Remote access enabled" : "Remote access disabled");
373→      }
374→    },
375→    [saveSetting]
376→  );
377→
378→  async function handleRemoveDevice(device: PairedDevice) {
379→    try {
380→      await revokeDeviceMutation.mutateAsync(device.id);
381→      toast.success(`Removed "${device.name}"`);
382→    } catch (error) {
383→      toast.error(`Failed to remove device: ${getErrorMessage(error)}`);
384→    }
385→  }
386→
387→  // -- Derived values --
388→
389→  const relayStatus = relayQuery.data;
390→  const devices = devicesQuery.data ?? [];
391→
392→  // Derive web app URL from relay WebSocket URL
393→  // wss://relay.rundeus.com -> https://app.rundeus.com/connect/{serverId}
394→  const accessUrl = (() => {
395→    if (!relayStatus?.relayUrl || !relayStatus.serverId) return null;
396→    try {
397→      const url = new URL(relayStatus.relayUrl);
398→      const host = url.hostname;
399→      const domain = host.replace(/^relay\./, "app.");
400→      return `https://${domain}/connect/${relayStatus.serverId}`;
401→    } catch {
402→      return null;
403→    }
404→  })();
405→
406→  // -- Render --
407→
408→  return (
409→    <div className="space-y-6">
410→      {/* Header */}
411→      <div>
412→        <h3 className="text-base font-semibold">Connect</h3>
413→        <p className="text-muted-foreground mt-1 text-sm">
414→          Access your workspaces from your phone or another computer.
415→        </p>
416→      </div>
417→
418→      {/* Master toggle */}
419→      <div className="flex items-center justify-between">
420→        <div>
421→          <Label htmlFor="remote-access-toggle" className="text-sm">
422→            Enable remote access
423→          </Label>
424→          <p className="text-muted-foreground text-xs">
425→            Allow other devices to connect to this machine.
426→          </p>
427→        </div>
428→        <Switch id="remote-access-toggle" checked={enabled} onCheckedChange={handleToggle} />
429→      </div>
430→
431→      {/* ----- Everything below is gated on the toggle ----- */}
432→
433→      {enabled && (
434→        <>
435→          {/* Portal card -- hero element: URL + status */}
436→          {accessUrl && relayStatus && (
437→            <PortalCard
438→              url={accessUrl}
439→              connected={relayStatus.connected}
440→              clients={relayStatus.clients}
441→            />
442→          )}
443→
444→          {/* Disconnected state without URL */}
445→          {relayStatus && !accessUrl && (
446→            <div className="bg-muted/30 flex items-center gap-2.5 rounded-lg px-4 py-3">
447→              <span className="size-[7px] shrink-0 rounded-full bg-amber-400" />
448→              <span className="text-muted-foreground text-sm">
449→                {relayStatus.connected
450→                  ? "Connected — waiting for configuration..."
451→                  : "Connecting..."}
452→              </span>
453→            </div>
454→          )}
455→
456→          <Separator />
457→
458→          {/* Connect a Device button */}
459→          <div className="space-y-3">
460→            <Button variant="outline" size="sm" onClick={() => setDialogOpen(true)}>
461→              <Plus className="mr-1.5 size-3.5" />
462→              Connect a Device
463→            </Button>
464→          </div>
465→
466→          {/* Connect Device Dialog */}
467→          <ConnectDeviceDialog
468→            open={dialogOpen}
469→            onOpenChange={setDialogOpen}
470→            accessUrl={accessUrl}
471→            devices={devices}
472→          />
473→
474→          <Separator />
475→
476→          {/* Connected devices */}
477→          <div className="space-y-3">
478→            <div className="flex items-center gap-2">
479→              <h4 className="text-sm font-medium">Connected Devices</h4>
480→              {devices.length > 0 && (
481→                <Badge variant="secondary" className="text-[11px]">
482→                  {devices.length}
483→                </Badge>
484→              )}
485→            </div>
486→            <DevicesList
487→              devices={devices}
488→              onRemove={handleRemoveDevice}
489→              isRemoving={revokeDeviceMutation.isPending}
490→            />
491→          </div>
492→        </>
493→      )}
494→    </div>
495→  );
496→}
