import { useState, useEffect, useCallback } from "react";
import { QRCodeSVG } from "qrcode.react";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Separator } from "@/components/ui/separator";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from "@/components/ui/dialog";
import { toast } from "sonner";
import { Copy, Trash2, Smartphone, Monitor, Plus, Check, Link2 } from "lucide-react";
import { getErrorMessage } from "@shared/lib/errors";
import {
  usePairedDevices,
  useGeneratePairCode,
  useRevokeDevice,
  useRelayStatus,
} from "../../api/auth.queries";
import type { PairedDevice } from "../../api/auth.service";
import type { SettingsSectionProps } from "./types";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function timeAgo(dateStr: string): string {
  const diff = Date.now() - new Date(dateStr).getTime();
  const minutes = Math.floor(diff / 60_000);
  if (minutes < 1) return "just now";
  if (minutes < 60) return `${minutes}m ago`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}h ago`;
  const days = Math.floor(hours / 24);
  return `${days}d ago`;
}

function getDeviceIcon(ua: string | null) {
  if (!ua) return Monitor;
  const lower = ua.toLowerCase();
  if (lower.includes("mobile") || lower.includes("iphone") || lower.includes("android")) {
    return Smartphone;
  }
  return Monitor;
}

/** Build the full pairing URL for QR code. */
function buildPairUrl(accessUrl: string, code: string): string {
  // accessUrl is like https://app.rundeus.com/connect/{serverId}
  // Append ?pair=SOFT+TIGER (URL-encode the space as +)
  const encodedCode = code.replace(/ /g, "+");
  return `${accessUrl}?pair=${encodedCode}`;
}

// ---------------------------------------------------------------------------
// Sub-components
// ---------------------------------------------------------------------------

/**
 * Portal URL card with connection status.
 */
function PortalCard({
  url,
  connected,
  clients,
}: {
  url: string;
  connected: boolean;
  clients: number;
}) {
  return (
    <div className="border-border/60 bg-muted/30 space-y-3 rounded-xl border px-4 py-4">
      {/* Status line */}
      <div className="flex items-center gap-2.5">
        <span
          className={`size-[7px] shrink-0 rounded-full ${
            connected ? "bg-emerald-500 shadow-[0_0_6px_rgba(16,185,129,0.35)]" : "bg-red-400"
          }`}
        />
        <span className="text-muted-foreground text-xs font-medium">
          {connected ? "Connected" : "Connecting..."}
        </span>
        {connected && clients > 0 && (
          <span className="text-muted-foreground/70 text-[11px]">
            &middot; {clients} {clients === 1 ? "device" : "devices"} online
          </span>
        )}
      </div>

      {/* URL + actions */}
      <div className="flex items-center gap-2">
        <p className="min-w-0 flex-1 truncate font-mono text-sm leading-relaxed">{url}</p>
        <Button
          variant="ghost"
          size="icon"
          className="size-7 shrink-0"
          onClick={() => {
            navigator.clipboard.writeText(url);
            toast.success("URL copied");
          }}
          title="Copy URL"
        >
          <Copy className="size-3.5" />
        </Button>
      </div>
    </div>
  );
}

/**
 * Connect Device Dialog -- shows QR code + code + countdown.
 * Eagerly generates a code on open.
 */
function ConnectDeviceDialog({
  open,
  onOpenChange,
  accessUrl,
  devices,
}: {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  accessUrl: string | null;
  devices: PairedDevice[];
}) {
  const generateCodeMutation = useGeneratePairCode();
  const [pairCode, setPairCode] = useState<string | null>(null);
  const [codeExpiresAt, setCodeExpiresAt] = useState(0);
  const [countdown, setCountdown] = useState(0);
  const [prevDeviceCount, setPrevDeviceCount] = useState(devices.length);
  const [showSuccess, setShowSuccess] = useState(false);

  // Eagerly generate code when dialog opens
  useEffect(() => {
    if (open && !pairCode && !generateCodeMutation.isPending) {
      generateCodeMutation
        .mutateAsync()
        .then((result) => {
          setPairCode(result.code);
          setCodeExpiresAt(Date.now() + result.expires_in_seconds * 1000);
        })
        .catch((error) => {
          toast.error(`Failed to generate code: ${getErrorMessage(error)}`);
        });
    }
    // Reset state when closing
    if (!open) {
      setPairCode(null);
      setCodeExpiresAt(0);
      setCountdown(0);
      setShowSuccess(false);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [open]);

  // Countdown timer
  useEffect(() => {
    if (!pairCode || codeExpiresAt <= 0) return;
    const tick = () => {
      const remaining = Math.max(0, Math.ceil((codeExpiresAt - Date.now()) / 1000));
      setCountdown(remaining);
      if (remaining <= 0) {
        setPairCode(null);
        setCodeExpiresAt(0);
      }
    };
    tick();
    const interval = setInterval(tick, 1000);
    return () => clearInterval(interval);
  }, [pairCode, codeExpiresAt]);

  // Detect successful pairing via device count change
  useEffect(() => {
    if (open && devices.length > prevDeviceCount) {
      setShowSuccess(true);
      // Auto-close after 2 seconds
      const timer = setTimeout(() => {
        onOpenChange(false);
      }, 2000);
      return () => clearTimeout(timer);
    }
    setPrevDeviceCount(devices.length);
    return undefined;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [devices.length, open]);

  const pairUrl = accessUrl && pairCode ? buildPairUrl(accessUrl, pairCode) : null;
  const minutes = Math.floor(countdown / 60);
  const isExpiringSoon = countdown > 0 && countdown < 120; // < 2 minutes

  function handleCopyCode() {
    if (!pairCode) return;
    navigator.clipboard.writeText(pairCode);
    toast.success("Code copied");
  }

  function handleCopyLink() {
    if (!pairUrl) return;
    navigator.clipboard.writeText(pairUrl);
    toast.success("Link copied");
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        {showSuccess ? (
          /* Success state */
          <div className="flex flex-col items-center gap-4 py-8">
            <div className="bg-emerald-500/10 flex size-16 items-center justify-center rounded-full">
              <Check className="size-8 text-emerald-500" />
            </div>
            <div className="text-center">
              <DialogTitle className="text-lg font-semibold">Device Connected</DialogTitle>
              <DialogDescription className="text-muted-foreground mt-1 text-sm">
                Your device has been connected successfully.
              </DialogDescription>
            </div>
          </div>
        ) : (
          /* Code + QR state */
          <>
            <DialogHeader className="text-center">
              <DialogTitle>Connect a Device</DialogTitle>
              <DialogDescription>
                Scan the QR code or enter the code on your other device.
              </DialogDescription>
            </DialogHeader>

            <div className="flex flex-col items-center gap-5 pt-2">
              {/* QR Code -- hero element */}
              {pairUrl ? (
                <div className="bg-white rounded-xl p-3">
                  <QRCodeSVG value={pairUrl} size={180} level="M" />
                </div>
              ) : (
                <div className="bg-muted/40 flex size-[204px] items-center justify-center rounded-xl">
                  <span className="text-muted-foreground text-sm">Generating...</span>
                </div>
              )}

              {/* Code display */}
              {pairCode ? (
                <p className="font-mono text-2xl font-bold tracking-wide">{pairCode}</p>
              ) : (
                <div className="bg-muted/40 h-8 w-40 animate-pulse rounded" />
              )}

              {/* Action buttons */}
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleCopyCode}
                  disabled={!pairCode}
                >
                  <Copy className="mr-1.5 size-3.5" />
                  Copy Code
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleCopyLink}
                  disabled={!pairUrl}
                >
                  <Link2 className="mr-1.5 size-3.5" />
                  Copy Link
                </Button>
              </div>

              {/* Countdown */}
              {countdown > 0 && (
                <p
                  className={`text-xs ${
                    isExpiringSoon ? "text-amber-500" : "text-muted-foreground"
                  }`}
                >
                  Expires in {minutes} {minutes === 1 ? "minute" : "minutes"}
                </p>
              )}
            </div>
          </>
        )}
      </DialogContent>
    </Dialog>
  );
}

