/**
 * Connect Device Dialog -- shows QR code + code + countdown.
 * Eagerly generates a code on open.
 */
function ConnectDeviceDialog({
  open,
  onOpenChange,
  accessUrl,
  devices,
}: {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  accessUrl: string | null;
  devices: PairedDevice[];
}) {
  const generateCodeMutation = useGeneratePairCode();
  const [pairCode, setPairCode] = useState<string | null>(null);
  const [codeExpiresAt, setCodeExpiresAt] = useState(0);
  const [countdown, setCountdown] = useState(0);
  const [prevDeviceCount, setPrevDeviceCount] = useState(devices.length);
  const [showSuccess, setShowSuccess] = useState(false);

  // Eagerly generate code when dialog opens
  useEffect(() => {
    if (open && !pairCode && !generateCodeMutation.isPending) {
      generateCodeMutation
        .mutateAsync()
        .then((result) => {
          setPairCode(result.code);
          setCodeExpiresAt(Date.now() + result.expires_in_seconds * 1000);
        })
        .catch((error) => {
          toast.error(`Failed to generate code: ${getErrorMessage(error)}`);
        });
    }
    // Reset state when closing
    if (!open) {
      setPairCode(null);
      setCodeExpiresAt(0);
      setCountdown(0);
      setShowSuccess(false);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [open]);

  // Countdown timer
  useEffect(() => {
    if (!pairCode || codeExpiresAt <= 0) return;
    const tick = () => {
      const remaining = Math.max(0, Math.ceil((codeExpiresAt - Date.now()) / 1000));
      setCountdown(remaining);
      if (remaining <= 0) {
        setPairCode(null);
        setCodeExpiresAt(0);
      }
    };
    tick();
    const interval = setInterval(tick, 1000);
    return () => clearInterval(interval);
  }, [pairCode, codeExpiresAt]);

  // Detect successful pairing via device count change
  useEffect(() => {
    if (open && devices.length > prevDeviceCount) {
      setShowSuccess(true);
      // Auto-close after 2 seconds
      const timer = setTimeout(() => {
        onOpenChange(false);
      }, 2000);
      return () => clearTimeout(timer);
    }
    setPrevDeviceCount(devices.length);
    return undefined;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [devices.length, open]);

  const pairUrl = accessUrl && pairCode ? buildPairUrl(accessUrl, pairCode) : null;
  const minutes = Math.floor(countdown / 60);
  const isExpiringSoon = countdown > 0 && countdown < 120; // < 2 minutes

  function handleCopyCode() {
    if (!pairCode) return;
    navigator.clipboard.writeText(pairCode);
    toast.success("Code copied");
  }

  function handleCopyLink() {
    if (!pairUrl) return;
    navigator.clipboard.writeText(pairUrl);
    toast.success("Link copied");
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        {showSuccess ? (
          /* Success state */
          <div className="flex flex-col items-center gap-4 py-8">
            <div className="bg-emerald-500/10 flex size-16 items-center justify-center rounded-full">
              <Check className="size-8 text-emerald-500" />
            </div>
            <div className="text-center">
              <DialogTitle className="text-lg font-semibold">Device Connected</DialogTitle>
              <DialogDescription className="text-muted-foreground mt-1 text-sm">
                Your device has been connected successfully.
              </DialogDescription>
            </div>
          </div>
        ) : (
          /* Code + QR state */
          <>
            <DialogHeader className="text-center">
              <DialogTitle>Connect a Device</DialogTitle>
              <DialogDescription>
                Scan the QR code or enter the code on your other device.
              </DialogDescription>
            </DialogHeader>

            <div className="flex flex-col items-center gap-5 pt-2">
              {/* QR Code -- hero element */}
              {pairUrl ? (
                <div className="bg-white rounded-xl p-3">
                  <QRCodeSVG value={pairUrl} size={180} level="M" />
                </div>
              ) : (
                <div className="bg-muted/40 flex size-[204px] items-center justify-center rounded-xl">
                  <span className="text-muted-foreground text-sm">Generating...</span>
                </div>
              )}

              {/* Code display */}
              {pairCode ? (
                <p className="font-mono text-2xl font-bold tracking-wide">{pairCode}</p>
              ) : (
                <div className="bg-muted/40 h-8 w-40 animate-pulse rounded" />
              )}

              {/* Action buttons */}
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleCopyCode}
                  disabled={!pairCode}
                >
                  <Copy className="mr-1.5 size-3.5" />
                  Copy Code
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleCopyLink}
                  disabled={!pairUrl}
                >
                  <Link2 className="mr-1.5 size-3.5" />
                  Copy Link
                </Button>
              </div>

              {/* Countdown */}
              {countdown > 0 && (
                <p
                  className={`text-xs ${
                    isExpiringSoon ? "text-amber-500" : "text-muted-foreground"
                  }`}
                >
                  Expires in {minutes} {minutes === 1 ? "minute" : "minutes"}
                </p>
              )}
            </div>
          </>
        )}
      </DialogContent>
    </Dialog>
  );
}

