// ---------------------------------------------------------------------------
// Page states
// ---------------------------------------------------------------------------

/** Auto-connecting view — shown when QR/link provides the code. */
function ConnectingView() {
  return (
    <m.div
      key="connecting"
      className="flex flex-col items-center gap-6"
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
