416→export function PairGatePage({ onPaired, serverId }: PairGatePageProps) {
417→  const prefill = getPairFromUrl();
418→  const isAutoConnect = prefill !== null;
419→
420→  const [code, setCode] = useState(prefill ?? "");
421→  const [error, setError] = useState<string | null>(null);
422→  const [pageState, setPageState] = useState<PageState>(isAutoConnect ? "connecting" : "idle");
423→
424→  const autoSubmitTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
425→  const pairedRef = useRef(false);
426→  const reduced = useReducedMotion();
427→
428→  const submitCode = useCallback(
429→    async (rawCode: string) => {
430→      const normalized = normalizeCode(rawCode);
431→      if (!normalized) return;
432→
433→      setError(null);
434→      setPageState("connecting");
435→
436→      const deviceName = navigator.userAgent.includes("Mobile") ? "Mobile Browser" : "Web Browser";
437→
438→      try {
439→        if (isRelayMode()) {
440→          const resolvedServerId = serverId || getServerIdFromUrl();
441→          if (!resolvedServerId) {
442→            setError("Unable to connect. Try opening the link from your desktop app again.");
443→            setPageState("error");
444→            return;
445→          }
446→          const result = await pairViaRelay(resolvedServerId, normalized, deviceName);
447→
448→          // Show success state, then navigate
449→          pairedRef.current = true;
450→          setPageState("success");
451→          setTimeout(() => onPaired(result.token, deviceName), SUCCESS_HOLD_MS);
452→        } else {
453→          const data = await pairViaDirect(normalized, deviceName);
454→
455→          pairedRef.current = true;
456→          setPageState("success");
457→          setTimeout(() => onPaired(data.token, data.device?.name), SUCCESS_HOLD_MS);
458→        }
459→      } catch (err) {
460→        setError(err instanceof Error ? err.message : "Unable to connect. Try again.");
461→        setPageState("error");
462→      }
463→    },
464→    [onPaired, serverId]
465→  );
466→
467→  // Auto-submit on mount if code came from URL
468→  useEffect(() => {
469→    if (isAutoConnect && prefill) {
470→      submitCode(prefill);
471→    }
472→    // eslint-disable-next-line react-hooks/exhaustive-deps
473→  }, []);
474→
475→  function handleSubmit(e: React.FormEvent) {
476→    e.preventDefault();
477→    submitCode(code);
478→  }
479→
480→  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
481→    setCode(e.target.value.toUpperCase());
482→    setError(null);
483→  }
484→
485→  function handlePaste(e: React.ClipboardEvent<HTMLInputElement>) {
486→    const pasted = e.clipboardData.getData("text");
487→    const resolved = extractCodeFromPastedUrl(pasted) ?? normalizeCode(pasted);
488→    if (!resolved) return;
489→
490→    e.preventDefault();
491→    setCode(resolved);
492→    setError(null);
493→
494→    if (autoSubmitTimer.current) clearTimeout(autoSubmitTimer.current);
495→    autoSubmitTimer.current = setTimeout(() => submitCode(resolved), 300);
496→  }
497→
498→  function handleRetryAutoConnect() {
499→    if (prefill) {
500→      setError(null);
501→      submitCode(prefill);
502→    } else {
503→      // Fall back to manual entry
504→      setPageState("idle");
505→      setError(null);
506→    }
507→  }
508→
509→  const codeIsValid = normalizeCode(code) !== null;
510→
511→  // Determine which view to render
512→  function renderContent() {
513→    // Auto-connect path: connecting or error
514→    if (isAutoConnect && pageState === "connecting") {
515→      return <ConnectingView />;
516→    }
517→
518→    if (pageState === "success") {
519→      return <SuccessView reduced={reduced} />;
520→    }
521→
522→    if (isAutoConnect && pageState === "error") {
523→      return (
524→        <AutoConnectErrorView
525→          error={error ?? "Unable to connect."}
526→          onRetry={handleRetryAutoConnect}
527→        />
528→      );
529→    }
530→
531→    // Manual entry path
532→    return (
533→      <ManualEntryView
534→        code={code}
535→        error={pageState === "error" ? error : null}
536→        isPending={pageState === "connecting"}
537→        codeIsValid={codeIsValid}
538→        onChange={handleChange}
539→        onPaste={handlePaste}
540→        onSubmit={handleSubmit}
541→      />
542→    );
543→  }
544→
545→  return (
546→    <div className="bg-background flex min-h-screen items-center justify-center p-4">
547→      <AnimatePresence mode="wait">
548→        {renderContent()}
549→      </AnimatePresence>
