 31→function timeAgo(dateStr: string): string {
 32→  const diff = Date.now() - new Date(dateStr).getTime();
 33→  const minutes = Math.floor(diff / 60_000);
 34→  if (minutes < 1) return "just now";
 35→  if (minutes < 60) return `${minutes}m ago`;
 36→  const hours = Math.floor(minutes / 60);
 37→  if (hours < 24) return `${hours}h ago`;
 38→  const days = Math.floor(hours / 24);
 39→  return `${days}d ago`;
 40→}
 41→
 42→function getDeviceIcon(ua: string | null) {
 43→  if (!ua) return Monitor;
 44→  const lower = ua.toLowerCase();
 45→  if (lower.includes("mobile") || lower.includes("iphone") || lower.includes("android")) {
 46→    return Smartphone;
 47→  }
 48→  return Monitor;
 49→}
 50→
 51→/** Build the full pairing URL for QR code. */
 52→function buildPairUrl(accessUrl: string, code: string): string {
 53→  // accessUrl is like https://app.rundeus.com/connect/{serverId}
 54→  // Append ?pair=SOFT+TIGER (URL-encode the space as +)
 55→  const encodedCode = code.replace(/ /g, "+");
 56→  return `${accessUrl}?pair=${encodedCode}`;
 57→}
