114→/**
115→ * Connect Device Dialog -- shows QR code + code + countdown.
116→ * Code state is owned by the parent so it survives close/reopen.
117→ */
118→function ConnectDeviceDialog({
119→  open,
120→  onOpenChange,
121→  accessUrl,
122→  pairCode,
123→  countdown,
124→  isGenerating,
125→  onGenerate,
126→  devices,
127→}: {
128→  open: boolean;
129→  onOpenChange: (open: boolean) => void;
130→  accessUrl: string | null;
131→  pairCode: string | null;
132→  countdown: number;
133→  isGenerating: boolean;
134→  onGenerate: () => void;
135→  devices: PairedDevice[];
136→}) {
137→  const [prevDeviceCount, setPrevDeviceCount] = useState(devices.length);
138→  const [showSuccess, setShowSuccess] = useState(false);
139→
140→  // Generate code on first open if none exists
141→  useEffect(() => {
142→    if (open && !pairCode && !isGenerating) {
143→      onGenerate();
144→    }
145→    if (!open) {
146→      setShowSuccess(false);
147→    }
148→    // eslint-disable-next-line react-hooks/exhaustive-deps
149→  }, [open]);
150→
151→  // Detect successful pairing via device count change
152→  useEffect(() => {
153→    if (open && devices.length > prevDeviceCount) {
154→      setShowSuccess(true);
155→      const timer = setTimeout(() => onOpenChange(false), 2000);
156→      return () => clearTimeout(timer);
157→    }
158→    setPrevDeviceCount(devices.length);
159→    return undefined;
160→    // eslint-disable-next-line react-hooks/exhaustive-deps
161→  }, [devices.length, open]);
162→
163→  const pairUrl = accessUrl && pairCode ? buildPairUrl(accessUrl, pairCode) : null;
164→  const minutes = Math.floor(countdown / 60);
165→  const isExpiringSoon = countdown > 0 && countdown < 120;
166→
167→  function handleCopyCode() {
168→    if (!pairCode) return;
169→    navigator.clipboard.writeText(pairCode);
170→    toast.success("Code copied");
171→  }
172→
173→  function handleCopyLink() {
174→    if (!pairUrl) return;
175→    navigator.clipboard.writeText(pairUrl);
176→    toast.success("Link copied");
177→  }
178→
179→  return (
