186→            </div>
187→            <div className="text-center">
188→              <DialogTitle className="text-lg font-semibold">Device Connected</DialogTitle>
189→              <DialogDescription className="text-muted-foreground mt-1 text-sm">
190→                You can now access your workspaces from this device.
191→              </DialogDescription>
192→            </div>
193→          </div>
194→        ) : (
195→          <>
196→            <DialogHeader className="text-center">
197→              <DialogTitle>Connect a Device</DialogTitle>
198→              <DialogDescription>
199→                Scan the QR code or enter the code on your other device.
200→              </DialogDescription>
201→            </DialogHeader>
202→
203→            <div className="flex flex-col items-center gap-5 pt-2">
