322→export function AccessSection({ settings, saveSetting }: SettingsSectionProps) {
323→  const enabled = settings.remote_access_enabled === true;
324→
325→  // Remote access queries -- only active when enabled
326→  const devicesQuery = usePairedDevices(enabled);
327→  const relayQuery = useRelayStatus(enabled);
328→  const generateCodeMutation = useGeneratePairCode();
329→  const revokeDeviceMutation = useRevokeDevice();
330→
331→  // Dialog state
332→  const [dialogOpen, setDialogOpen] = useState(false);
333→
334→  // Code state -- lives here so it survives dialog close/reopen
335→  const [pairCode, setPairCode] = useState<string | null>(null);
336→  const [codeExpiresAt, setCodeExpiresAt] = useState(0);
337→  const [countdown, setCountdown] = useState(0);
338→
339→  // Countdown timer -- runs regardless of dialog open state
340→  useEffect(() => {
341→    if (!pairCode || codeExpiresAt <= 0) return;
342→    const tick = () => {
343→      const remaining = Math.max(0, Math.ceil((codeExpiresAt - Date.now()) / 1000));
344→      setCountdown(remaining);
345→      if (remaining <= 0) {
346→        setPairCode(null);
347→        setCodeExpiresAt(0);
348→      }
349→    };
350→    tick();
351→    const interval = setInterval(tick, 1000);
352→    return () => clearInterval(interval);
353→  }, [pairCode, codeExpiresAt]);
354→
355→  async function handleGenerateCode() {
356→    try {
357→      const result = await generateCodeMutation.mutateAsync();
358→      setPairCode(result.code);
359→      setCodeExpiresAt(Date.now() + result.expires_in_seconds * 1000);
360→    } catch (error) {
361→      toast.error(`Failed to generate code: ${getErrorMessage(error)}`);
362→    }
363→  }
364→
365→  // -- Handlers --
366→
367→  const handleToggle = useCallback(
368→    async (on: boolean) => {
369→      const ok = await saveSetting("remote_access_enabled", on);
370→      if (ok) {
371→        toast.success(on ? "Device connections enabled" : "Device connections disabled");
372→      }
373→    },
374→    [saveSetting]
375→  );
376→
377→  async function handleRemoveDevice(device: PairedDevice) {
378→    try {
379→      await revokeDeviceMutation.mutateAsync(device.id);
380→      toast.success(`Removed "${device.name}"`);
381→    } catch (error) {
382→      toast.error(`Failed to remove device: ${getErrorMessage(error)}`);
383→    }
384→  }
385→
386→  // -- Derived values --
387→
388→  const relayStatus = relayQuery.data;
389→  const devices = devicesQuery.data ?? [];
390→
391→  // Derive web app URL from relay WebSocket URL
392→  // wss://relay.rundeus.com -> https://app.rundeus.com/connect/{serverId}
393→  const accessUrl = (() => {
394→    if (!relayStatus?.relayUrl || !relayStatus.serverId) return null;
395→    try {
396→      const url = new URL(relayStatus.relayUrl);
397→      const host = url.hostname;
398→      const domain = host.replace(/^relay\./, "app.");
399→      return `https://${domain}/connect/${relayStatus.serverId}`;
400→    } catch {
401→      return null;
402→    }
403→  })();
404→
405→  // -- Render --
406→
407→  return (
408→    <div className="space-y-6">
409→      {/* Header */}
410→      <div>
411→        <h3 className="text-base font-semibold">Remote Access</h3>
412→        <p className="text-muted-foreground mt-1 text-sm">
413→          Access your workspaces from your phone or another computer.
414→        </p>
415→      </div>
416→
417→      {/* Master toggle */}
418→      <div className="flex items-center justify-between">
419→        <div>
420→          <Label htmlFor="remote-access-toggle" className="text-sm">
421→            Enable remote access
422→          </Label>
423→          <p className="text-muted-foreground text-xs">
424→            Allow other devices to connect to this machine.
425→          </p>
426→        </div>
427→        <Switch id="remote-access-toggle" checked={enabled} onCheckedChange={handleToggle} />
428→      </div>
429→
430→      {/* ----- Everything below is gated on the toggle ----- */}
431→
432→      {enabled && (
433→        <>
434→          {/* Portal card -- hero element: URL + status */}
435→          {accessUrl && relayStatus && (
436→            <PortalCard
437→              url={accessUrl}
438→              connected={relayStatus.connected}
439→              clients={relayStatus.clients}
440→            />
441→          )}
442→
443→          {/* Disconnected state without URL */}
444→          {relayStatus && !accessUrl && (
445→            <div className="bg-muted/30 flex items-center gap-2.5 rounded-lg px-4 py-3">
446→              <span className="size-[7px] shrink-0 rounded-full bg-amber-400" />
447→              <span className="text-muted-foreground text-sm">
448→                {relayStatus.connected ? "Setting up..." : "Connecting..."}
449→              </span>
450→            </div>
451→          )}
452→
453→          <Separator />
454→
455→          {/* Connect a Device button */}
456→          <div className="space-y-3">
457→            <Button variant="outline" size="sm" onClick={() => setDialogOpen(true)}>
458→              <Plus className="mr-1.5 size-3.5" />
459→              Connect a Device
460→            </Button>
461→          </div>
462→
463→          {/* Connect Device Dialog */}
464→          <ConnectDeviceDialog
465→            open={dialogOpen}
466→            onOpenChange={setDialogOpen}
467→            accessUrl={accessUrl}
468→            pairCode={pairCode}
469→            countdown={countdown}
470→            isGenerating={generateCodeMutation.isPending}
471→            onGenerate={handleGenerateCode}
472→            devices={devices}
473→          />
474→
475→          <Separator />
476→
477→          {/* Connected devices */}
478→          <div className="space-y-3">
479→            <div className="flex items-center gap-2">
480→              <h4 className="text-sm font-medium">Connected Devices</h4>
481→              {devices.length > 0 && (
