402→export function PairGatePage({ onPaired, serverId }: PairGatePageProps) {
403→  const prefill = getPairFromUrl();
404→  const isAutoConnect = prefill !== null;
405→
406→  const [code, setCode] = useState(prefill ?? "");
407→  const [error, setError] = useState<string | null>(null);
408→  const [pageState, setPageState] = useState<PageState>(isAutoConnect ? "connecting" : "idle");
409→
410→  const autoSubmitTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
411→  const reduced = useReducedMotion();
412→
413→  const submitCode = useCallback(
414→    async (rawCode: string) => {
415→      const normalized = normalizeCode(rawCode);
416→      if (!normalized) return;
417→
418→      setError(null);
419→      setPageState("connecting");
420→
421→      const deviceName = navigator.userAgent.includes("Mobile") ? "Mobile Browser" : "Web Browser";
422→
423→      try {
424→        let token: string;
425→        let resolvedName: string | undefined = deviceName;
426→
427→        if (isRelayMode()) {
428→          const resolvedServerId = serverId || getServerIdFromUrl();
429→          if (!resolvedServerId) {
430→            setError("Unable to connect. Try opening the link from your desktop app again.");
431→            setPageState("error");
432→            return;
433→          }
434→          const result = await pairViaRelay(resolvedServerId, normalized, deviceName);
435→          token = result.token;
436→        } else {
437→          const data = await pairViaDirect(normalized, deviceName);
438→          token = data.token;
439→          resolvedName = data.device?.name;
440→        }
441→
442→        // Show success state, then navigate
443→        setPageState("success");
444→        setTimeout(() => onPaired(token, resolvedName), SUCCESS_HOLD_MS);
445→      } catch (err) {
446→        setError(err instanceof Error ? err.message : "Unable to connect. Try again.");
447→        setPageState("error");
448→      }
449→    },
450→    [onPaired, serverId]
451→  );
452→
453→  // Auto-submit on mount if code came from URL
454→  useEffect(() => {
455→    if (prefill) {
456→      submitCode(prefill);
457→    }
458→    // eslint-disable-next-line react-hooks/exhaustive-deps
459→  }, []);
460→
461→  function handleSubmit(e: React.FormEvent) {
462→    e.preventDefault();
463→    submitCode(code);
464→  }
465→
466→  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
467→    setCode(e.target.value.toUpperCase());
468→    setError(null);
469→  }
470→
471→  function handlePaste(e: React.ClipboardEvent<HTMLInputElement>) {
472→    const pasted = e.clipboardData.getData("text");
473→    const resolved = extractCodeFromPastedUrl(pasted) ?? normalizeCode(pasted);
474→    if (!resolved) return;
475→
476→    e.preventDefault();
477→    setCode(resolved);
478→    setError(null);
479→
480→    if (autoSubmitTimer.current) clearTimeout(autoSubmitTimer.current);
481→    autoSubmitTimer.current = setTimeout(() => submitCode(resolved), 300);
482→  }
483→
484→  function handleRetryAutoConnect() {
485→    if (prefill) {
486→      submitCode(prefill);
487→    } else {
488→      setPageState("idle");
489→      setError(null);
490→    }
491→  }
492→
493→  const codeIsValid = normalizeCode(code) !== null;
494→
495→  // Determine which view to render
496→  function renderContent() {
497→    // Auto-connect path: connecting or error
498→    if (isAutoConnect && pageState === "connecting") {
499→      return <ConnectingView />;
500→    }
501→
502→    if (pageState === "success") {
503→      return <SuccessView reduced={reduced} />;
504→    }
505→
506→    if (isAutoConnect && pageState === "error") {
507→      return (
508→        <AutoConnectErrorView
509→          error={error ?? "Unable to connect."}
510→          onRetry={handleRetryAutoConnect}
511→        />
512→      );
513→    }
514→
515→    // Manual entry path
516→    return (
517→      <ManualEntryView
518→        code={code}
519→        error={pageState === "error" ? error : null}
520→        isPending={pageState === "connecting"}
521→        codeIsValid={codeIsValid}
522→        onChange={handleChange}
523→        onPaste={handlePaste}
524→        onSubmit={handleSubmit}
525→      />
526→    );
527→  }
528→
529→  return (
530→    <div className="bg-background flex min-h-screen items-center justify-center p-4">
531→      <AnimatePresence mode="wait">{renderContent()}</AnimatePresence>
532→    </div>
533→  );
534→}
