 17→import { describe, it, expect, beforeAll, beforeEach, afterAll, vi } from "vitest";
 18→
 19→// ---- Hoisted setup: create DB in vi.hoisted scope so vi.mock can reference it ----
 20→
 21→const { testDb, TEST_DB_PATH, TEST_DIR } = vi.hoisted(() => {
 22→  // Import better-sqlite3 synchronously in the hoisted block.
 23→  // vi.hoisted runs before any vi.mock factory but after module imports are resolved.
 24→  const Database = require("better-sqlite3");
 25→  const os = require("os");
 26→  const path = require("path");
 27→  const fs = require("fs");
 28→
 29→  // Use a real temp directory so PREFS_PATH (derived from DB_PATH) resolves correctly.
 30→  // Settings are now stored in preferences.json, not the settings DB table.
 31→  const testDir = path.join(os.tmpdir(), `opendevs-test-auth-flow-${process.pid}-${Date.now()}`);
 32→  fs.mkdirSync(testDir, { recursive: true });
 33→  const dbPath = path.join(testDir, "opendevs.db");
 34→
 35→  const db = new Database(dbPath);
 36→  db.pragma("journal_mode = WAL");
 37→  db.pragma("foreign_keys = ON");
 38→  return { testDb: db, TEST_DB_PATH: dbPath, TEST_DIR: testDir };
 39→});
 40→
 41→// Mock getDatabase to return our test DB.
 42→// This must be vi.mock (hoisted) so every module that imports getDatabase gets the test DB.
 43→vi.mock("../../src/lib/database", () => ({
 44→  getDatabase: () => testDb,
 45→  initDatabase: () => testDb,
 46→  closeDatabase: () => {},
 47→  DB_PATH: TEST_DB_PATH,
 48→}));
 49→
 50→// Mock server.ts to prevent side-effect execution (it calls initDatabase + serve at import time).
 51→// health.ts imports getServerPort from server.ts, which triggers the entire server boot.
 52→vi.mock("../../src/server", () => ({
 53→  getServerPort: () => 0,
 54→}));
